import{b as e}from"./vendor-react-HvrGhNGd.js";function n({title:o,titleId:i,...a},t){return e.createElement("svg",Object.assign({xmlns:"http://www.w3.org/2000/svg",fill:"none",viewBox:"0 0 24 24",strokeWidth:1.5,stroke:"currentColor","aria-hidden":"true","data-slot":"icon",ref:t,"aria-labelledby":i},a),o?e.createElement("title",{id:i},o):null,e.createElement("path",{strokeLinecap:"round",strokeLinejoin:"round",d:"M10.5 6h9.75M10.5 6a1.5 1.5 0 1 1-3 0m3 0a1.5 1.5 0 1 0-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 0 1-3 0m3 0a1.5 1.5 0 0 0-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 0 1-3 0m3 0a1.5 1.5 0 0 0-3 0m-9.75 0h9.75"}))}const d=e.forwardRef(n);function r({title:o,titleId:i,...a},t){return e.createElement("svg",Object.assign({xmlns:"http://www.w3.org/2000/svg",fill:"none",viewBox:"0 0 24 24",strokeWidth:1.5,stroke:"currentColor","aria-hidden":"true","data-slot":"icon",ref:t,"aria-labelledby":i},a),o?e.createElement("title",{id:i},o):null,e.createElement("path",{strokeLinecap:"round",strokeLinejoin:"round",d:"m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z"}))}const l=e.forwardRef(r),c=JSON.parse(`[{"id":0,"name":"Dark Sense","code":"darksense","survivorCode":"all","survivorName":"All","description":"Unlocks potential in one's Aura-reading abilities.\\nWhenever a Generator is completed, the next time the Killer comes within 24 metres of you, their Aura is revealed to you for 5/7/10 seconds.\\n\\"Take it from an old-timer: Slow down, don't rush and try not to worry so much! The best way to beat him is to know how he thinks.\\" — Murf, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconPerks_darkSense.png"},{"id":1,"name":"Déjà Vu","code":"dejavu","survivorCode":"all","survivorName":"All","description":"Unlocks potential in one's Aura-reading ability.\\nThe Auras of 3 Generators in closest proximity to each other are revealed to you for 30/45/60 seconds, both at the start of the Trial and each time a Generator is completed.\\nIf you are holding a Map that can track Objectives, Generators revealed by Déjà Vu are added to the Map.\\nIncreases the Repair speed of the Generators by +5 %.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/89/IconPerks_dejaVu.png"},{"id":2,"name":"Guardian","code":"guardian","survivorCode":"all","survivorName":"All","description":"You risk it all to help those in need.\\nWhen you unhook a Survivor, the rescued Survivor benefits from the following effects for 4/6/8 seconds:\\nScratch Marks and Pools of Blood are suppressed.\\n7% Haste Status Effect, boosting their Movement speed.\\nGuardian reveals the Killer's Aura to you for 8 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/23/IconPerks_guardian.png"},{"id":3,"name":"Hope","code":"hope","survivorCode":"all","survivorName":"All","description":"The growing odds of a successful escape fill you with hope and give you wings.\\nAs soon as the Exit Gates are powered, gain a 5/6/7 % Haste Status Effect.\\n\\"Buckle up, fuckos! Let's roll.\\" — Nikki, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/18/IconPerks_hope.png"},{"id":4,"name":"Inner Healing","code":"innerhealing","survivorCode":"all","survivorName":"All","description":"You look inwards and trust your instincts when you feel lost and alone.\\nEach time you cleanse a Totem, Inner Healing activates:\\nYou are automatically healed 1 Health State when hiding inside a Locker for 10/9/8 seconds while injured or suffering from the Deep Wound Status Effect.\\nInner Healing does not activate if you currently suffer from the Broken.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/df/IconPerks_innerHealing.png"},{"id":5,"name":"Kindred","code":"kindred","survivorCode":"all","survivorName":"All","description":"Unlocks potential in your Aura-reading ability:\\nWhile you are hooked:\\nThe Auras of all Survivors are revealed to one another.\\nWhenever the Killer is within 8/12/16 meters of your Hook, their Aura is revealed to all Survivors.\\nWhile any another Survivor is hooked:\\nThe Auras of all other Survivors are revealed to you.\\nWhenever the Killer is within 8/12/16 meters of the hooked Survivor, their Aura is revealed to you.\\n\\"Be kind to one another, We're all in this together\\" — Sujan, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a8/IconPerks_kindred.png"},{"id":6,"name":"Kinship","code":"kinship","survivorCode":"all","survivorName":"All","description":"The importance of friendship has given you strength.\\nWhile you are on the Hook in the Struggle Phase, Kinship activates:If another Survivor is within 16 meters of your Hook while Kinship is active, the Struggle Phase timer is paused for 26/30/34 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_camaraderie.png"},{"id":7,"name":"Lightweight","code":"lightweight","survivorCode":"all","survivorName":"All","description":"Your running is light and soft, making your tracks harder to follow.\\nScratch Marks begin to fade 3/4/5 seconds sooner and spawn more sporadically.\\n\\"Take it slow, he knows where you have been... just like I have always said: 'live slow and die old'.\\" — Dylan, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconPerks_lightweight.png"},{"id":8,"name":"No One Left Behind","code":"nooneleftbehind","survivorCode":"all","survivorName":"All","description":"It is inconceivable to leave someone behind.\\nOnce the Exit Gate are powered, No One Left Behind activates:\\nGain a 30/40/50 % Action Speed bonus to Unhooking and Healing other Survivors.\\nGrants 50/75/100 % bonus Bloodpoints for actions in the Altruism Category.\\nThe Auras of all other Survivors are revealed to you.\\nEach Survivor you unhook is granted a 7 % Haste Status Effect for 10 seconds.\\n\\"... yeah, no shit. But I believe we can outsmart and overthrow him if we work together. Don't be predictable and selfish!\\" — Clyde, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b0/IconPerks_noOneLeftBehind.png"},{"id":9,"name":"Plunderer's Instinct","code":"plunderersinstinct","survivorCode":"all","survivorName":"All","description":"Unlocks potential in your Aura-reading ability:\\nThe Auras of closed Chests and dropped Items in the environment within 16/24/32 meters of your location are revealed to you.\\nGrants a considerably better chance at finding an Item of a higher Rarity from Chests.\\n\\"The pioneers used to loot these babies for hours.\\" — Aizeyu, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/28/IconPerks_plunderersInstinct.png"},{"id":10,"name":"Premonition","code":"premonition","survivorCode":"all","survivorName":"All","description":"You have the undeniable capability to sense danger.\\nReceive an auditory warning upon looking in the Killer's direction within a 45° cone within 36 meters.\\nPremonition has a cool-down of 60/45/30 seconds each time it activates.\\n\\"I have a bad feeling about this!\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/39/IconPerks_premonition.png"},{"id":11,"name":"Renewal","code":"renewal","survivorCode":"all","survivorName":"All","description":"When you heal another Survivor for the equivalent of 1 Health State, Renewal activates:\\nThe next time you are unhooked or unhook yourself, you suffer from the Broken Status Effect until Renewal deactivates.\\nYou are automatically healed 1 Health State after 28/24/20 seconds.\\nWhile Renewal is active, the following conditions will deactivate it:\\nSuccessfully being healed by Renewal.\\nBeing put into the Dying State before the timer elapses.\\nRenewal does not activate if you already suffer from the Broken Status Effect.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7b/IconPerks_renewal.png"},{"id":12,"name":"Resilience","code":"resilience","survivorCode":"all","survivorName":"All","description":"You are motivated in dire situations.\\nIncreases your Action speeds in Repairing, Healing, Sabotaging, Unhooking, Vaulting, Cleansing, Opening, and Unlocking by 3/6/9% when in the Injured State.\\n\\"Focus, even in these desperate times.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ee/IconPerks_resilience.png"},{"id":13,"name":"Self-Aware","code":"selfaware","survivorCode":"all","survivorName":"All","description":"You know your weaknesses and refuse to hide from them.\\nYou walk 10/15/20% faster and can see your own Scratch Marks.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7c/IconPerks_fixated.png"},{"id":14,"name":"Situational Awareness","code":"situationalawareness","survivorCode":"all","survivorName":"All","description":"You are aware of your surroundings and share the information with others.\\nWhile repairing a Generator, its Aura is revealed in yellow to all other Survivors located within 32 meters.\\nIf the Killer downs a Survivor while you are repairing a Generator, you see the Auras of all other Survivors for 8/9/10 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/da/IconPerks_situationalAwareness.png"},{"id":15,"name":"Slippery Meat","code":"slipperymeat","survivorCode":"all","survivorName":"All","description":"You have developed an efficient way to get off Hooks.\\nGrants 3 additional Self-Unhook attempts.\\nIncreases the Self-Unhook chance by 2/3/4%.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconPerks_slipperyMeat.png"},{"id":16,"name":"Small Game","code":"smallgame","survivorCode":"all","survivorName":"All","description":"You have the undeniable capability to sense danger.\\nReceive an auditory warning upon looking in the direction of Totems in a 45° cone within 8/10/12 meters.\\nSmall Game has a cool-down of 14/12/10 seconds each time it activates.\\nFor each Dull or Hex Totem cleansed by any Player, Small Game gains 1 Token:\\nEach Token decreases the Detection cone's angle by 5°, down to a minimum of 20°.\\n\\"Nope.\\" — Andy, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/dc/IconPerks_smallGame.png"},{"id":17,"name":"Spine Chill","code":"spinechill","survivorCode":"all","survivorName":"All","description":"An unnatural tingle warns you of impending doom.\\nIf the Killer is within 36 metres of your location, Spine Chill activates, lighting up its icon.\\nIf there is a Terror Radius present, Spine Chill will reveal its intensity using its icon.\\nIf the Killer is within range and looking at you with a clear line of sight, you benefit from the following effect:\\nIncreases your Action speeds in Repairing, Healing, Sabotaging, Unhooking, Cleansing, Blessing, Opening, and Unlocking by 2/4/6 %.\\nThis effect lingers for 0.5 seconds.\\nSpine Chill reveals the current intensity of the Killer's Terror Radius.\\n\\"There is a voice that doesn't use words. Listen..\\" — Sassy, The Lost Tapes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/57/IconPerks_spineChill.png"},{"id":18,"name":"This Is Not Happening","code":"thisisnothappening","survivorCode":"all","survivorName":"All","description":"You perform at your best when you are under extreme stress.\\nIncreases the Success zone of Great Skill Checks while Repairing and Healing by 10/20/30% when in the Injured State.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/58/IconPerks_thisIsNotHappening.png"},{"id":19,"name":"We'll Make It","code":"wellmakeit","survivorCode":"all","survivorName":"All","description":"Helping others heightens your morale.\\nIncreases your Altruistic Healing speed by 100% for the next 30/60/90 seconds whenever you rescue another Survivor from a Hook.\\n\\"I am confident we can all escape in one piece if we help each other.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8a/IconPerks_wellMakeIt.png"},{"id":20,"name":"Bond","code":"bond","survivorCode":"dwightfairfield","survivorName":"Dwight Fairfield","description":"Unlocks potential in your Aura-reading ability:\\nThe Auras of all other Survivors within 20/28/36 meters of your location are revealed to you.\\n\\"We have to work as a team, I need you to survive so that I can survive!\\" — Dwight Fairfield","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a0/IconPerks_bond.png"},{"id":21,"name":"Prove Thyself","code":"provethyself","survivorCode":"dwightfairfield","survivorName":"Dwight Fairfield","description":"Increases your Repair speed by +15% for each other Survivor within 4 meters of your location, up to a maximum of +45%.\\nThis effect is also applied to all other Survivors within that range.\\nGrants 50/75/100% bonus Bloodpoints for Co-operative actions.\\nProve Thyself does not stack with other instances of itself.\\n\\"Show me what you can do!\\" — Dwight Fairfield","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0f/IconPerks_proveThyself.png"},{"id":22,"name":"Leader","code":"leader","survivorCode":"dwightfairfield","survivorName":"Dwight Fairfield","description":"You are able to organise a team to cooperate more efficiently.\\nIncreases the Action speeds of other Survivors in Healing, Sabotaging, Unhooking, Cleansing, Opening, and Unlocking by 15/20/25% while they are within 8 meters of your location.\\nThis effect lingers for 15 seconds when leaving Leader's range.\\nLeader does not stack with other instances of itself.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3d/IconPerks_leader.png"},{"id":23,"name":"Quick & Quiet","code":"quickandquiet","survivorCode":"megthomas","survivorName":"Meg Thomas","description":"You do not make as much noise as others when quickly vaulting over obstacles or hiding in Lockers.\\nSuppresses both the Loud Noise Notification and the sound effects triggered by rushing to vault Windows, Pallets, or rushing to enter or exit Lockers.\\nQuick & Quiet has a cool-down of 30/25/20 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_quickAndQuiet.png"},{"id":24,"name":"Sprint Burst","code":"sprintburst","survivorCode":"megthomas","survivorName":"Meg Thomas","description":"When starting to run, break into a sprint at 150 % of your normal Running Movement speed for 3 seconds.\\nSprint Burst causes the Exhausted Status Effect for 60/50/40 seconds.\\nSprint Burst cannot be used when Exhausted.\\n\\"See you if you can catch up...\\" — Meg Thomas","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e4/IconPerks_sprintBurst.png"},{"id":25,"name":"Adrenaline","code":"adrenaline","survivorCode":"megthomas","survivorName":"Meg Thomas","description":"You are fuelled by unexpecting energy when on the verge of escape.\\nOnce the Exit Gates are powered, instantly heal one Health State and sprint at 150% of your normal Running Movement speed for 5 seconds.\\nAdrenaline is on hold if you are disabled at the moment it triggers and will instead activate upon being freed.\\nIf playing against The Nightmare, Adrenaline will wake you from the Dream World upon activation.\\nAdrenaline ignores an existing Exhaustion timer, but causes the Exhausted Status Effect for 60/50/40 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconPerks_adrenaline.png"},{"id":26,"name":"Empathy","code":"empathy","survivorCode":"claudettemorel","survivorName":"Claudette Morel","description":"Unlocks potential in your Aura-reading ability:\\nThe Auras of Survivors in the Injured State or in the Dying State within 64/96/128 meters of your location are revealed to you.\\nEmpathy does not reveal the Aura of a Survivor being carried by the Killer.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ae/IconPerks_empathy.png"},{"id":27,"name":"Botany Knowledge","code":"bodanyknowledge","survivorCode":"claudettemorel","survivorName":"Claudette Morel","description":"You transform plants found around The Campfire into tinctures that slow down bleeding.\\nIncreases the Healing speed by 30/40/50 %.\\nReduces the Healing efficiency of Med-Kits by -20 %.\\n\\"Basic Botany Knowledge could save your life someday\\" — Claudette Morel","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1e/IconPerks_botanyKnowledge.png"},{"id":28,"name":"Self-Care","code":"selfcare","survivorCode":"claudettemorel","survivorName":"Claudette Morel","description":"Unlocks the ability to heal yourself without a Med-Kit at 25/30/35 % of the normal Healing speed.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b2/IconPerks_self-Care.png"},{"id":29,"name":"Iron Will","code":"ironwill","survivorCode":"jakepark","survivorName":"Jake Park","description":"You are able to concentrate and enter a meditative-like state to numb some pain.\\nLowers the volume of Grunts of Pain by 50/75/100%.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/58/IconPerks_ironWill.png"},{"id":30,"name":"Calm Spirit","code":"calmspirit","survivorCode":"jakepark","survivorName":"Jake Park","description":"Animals seem to trust you as they often stay calm in your presence.\\nPrevents Crows from being alerted by your proximity and flying off, unless they are being stepped on.\\nSuppresses the urge to scream from pain at all times.\\nSuppresses all noises related to interacting with Chests and Totems.\\nReduces the Action speeds for Unlocking, Cleansing, and Blessing by 40/35/30 %.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6c/IconPerks_calmSpirit.png"},{"id":31,"name":"Saboteur","code":"saboteur","survivorCode":"jakepark","survivorName":"Jake Park","description":"Unlocks potential in one's Aura-reading ability.\\nFor the duration of the Killer carrying another Survivor, you see the Auras of all Hooks within 56 metres of the pick-up location:\\nThe Auras of regular Hooks are revealed to you in white.\\nThe Auras of Scourge Hooks are revealed to you in yellow.\\nUnlocks the ability to sabotage Hooks without a Toolbox.\\nSabotaging a Hook without a Toolbox takes 2.5 seconds.\\nThe Sabotage action has a cool-down of 90/75/60 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0e/IconPerks_saboteur.png"},{"id":32,"name":"Balanced Landing","code":"balancedlanding","survivorCode":"neakarlsson","survivorName":"Nea Karlsson","description":"Your agility and cat-like relexes are incomparable.\\nWhen falling from great heights, you benefit from the following effects:\\nReduces the Stagger duration by 75%.\\nSuppresses Grunts of Exertion from falling.\\nUpon landing, break into a sprint at 150% of your normal Running Movement speed for 3 seconds.\\nBalanced Landing causes the Exhausted Status Effect for 60/50/40 seconds.\\nBalanced Landing cannot be used when Exhausted.\\n\\"I have jumped from higher places.\\" — Nea Karlsson","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5e/IconPerks_balancedLanding.png"},{"id":33,"name":"Urban Evasion","code":"urbanevasion","survivorCode":"neakarlsson","survivorName":"Nea Karlsson","description":"Years of evading the cops taught you a thing or two about stealth.\\nIncreases your Crouching Movement speed by 90/95/100%.\\n\\"The paint is still fresh but I am long gone.\\" — Nea Karlsson","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c7/IconPerks_urbanEvasion.png"},{"id":34,"name":"Streetwise","code":"streetwise","survivorCode":"neakarlsson","survivorName":"Nea Karlsson","description":"Long nights out taught you to do a lot with what you have got.\\nDecreases the Depletion rate of your Items by 15/20/25%.\\nStreetwise extends its effect to all other Survivors within 8 meters of your location and lingers for 15 seconds.\\n\\"You are doing it wrong! Let me show you how it is done.\\" — Nea Karlsson","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/IconPerks_streetwise.png"},{"id":35,"name":"Left Behind","code":"leftbehind","survivorCode":"williambilloverbeck","survivorName":"William \\"Bill\\" Overbeck","description":"You will get the job done... no matter the cost.\\nWhen you are the last Survivor remaining in the Trial, the Aura of the Hatch is revealed to you when you are within 24/28/32 meters.\\n\\"I'm not horse-shittin' around. I'm doing this alone!\\" — Bill Overbeck","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_leftBehind.png"},{"id":36,"name":"Borrowed Time","code":"borrowedtime","survivorCode":"williambilloverbeck","survivorName":"William \\"Bill\\" Overbeck","description":"You are fuelled with an unexpected energy when saving an Ally from a Hook.\\nIncreases the duration of the Endurance Status Effect for the unhooked Survivor by 6/8/10 seconds.\\nIncreases the duration of the Haste Status Effect for the unhooked Survivor by +10 seconds.\\nBorrowed Time's effects are cancelled prematurely if the unhooked Survivor performs a Conspicuous Action.\\n\\"Probably stings like hell, but it ain't gonna kill ya. Up and at 'em soldier. Time to move!\\" — Bill Overbeck","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a3/IconPerks_borrowedTime.png"},{"id":37,"name":"Unbreakable","code":"unbreakable","survivorCode":"williambilloverbeck","survivorName":"William \\"Bill\\" Overbeck","description":"Past battles have taught you a thing or two about survival.\\nOnce per Trial, you can completely recover from the Dying State.\\nYour Recovery speed is increased by 25/30/35%.\\n\\"Goddammit, I am seriously FUBAR!\\" — Bill Overbeck","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4a/IconPerks_unbreakable.png"},{"id":38,"name":"We're Gonna Live Forever","code":"weregonnaliveforever","survivorCode":"davidking","survivorName":"David King","description":"Your few friends deserve the best protection.\\nIncreases your Healing speed by 100 % when healing a dying Survivor.\\nWhen performing any of the following actions, We're Gonna Live Forever gains 1 Token:\\nSafely unhook another Survivor\\nTake a Protection Hit for an injured Survivor\\nStun or blind the Killer to rescue a carried Survivor\\nConsume 1 Token to grant the Endurance Status Effect for 6/8/10 seconds to any Survivor healed from the Dying State.\\n\\"Come on then, let's ave' it! I don't give a shit pal.\\" — David King","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b8/IconPerks_wereGonnaLiveForever.png"},{"id":39,"name":"Dead Hard","code":"deadhard","survivorCode":"davidking","survivorName":"David King","description":"Activate-able Perk.\\nYou can take a beating.\\nWhen Injured, tap into your adrenaline bank and dash forward quickly to avoid damage.\\nPress the Active Ability button while running to trigger the Endurance Status Effect for 0.5 seconds.\\nDead Hard causes the Exhausted Status Effect for 60/50/40 seconds\\nDead Hard cannot be used when Exhausted.\\n\\"We were walkin' through t'ginnel one night when a beer bottle flew past me, then another, and another. I thought to myself 'Gonna 'ave some fun 'ere lads, let's get stuck in!'. It were a right dust up, I swear down!\\" — David King","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/75/IconPerks_deadHard.png"},{"id":40,"name":"No Mither","code":"nomither","survivorCode":"davidking","survivorName":"David King","description":"Go on out, kid, it is just a scratch.\\nYour thick blood coagulates practically instantly.\\nYou suffer from the Broken Status Effect for the entire Trial, but benefit from the following effects:\\nPools of Blood are suppressed.\\nWhen injured or dying, Grunts of Pain are reduced by 25/50/75%.\\nYour Recovery speed is increased by 15/20/25 %.\\nYou can recover fully from the Dying.\\n\\"I lost it. Just lamped him one. They went and banned me didn't they. Went t'pub afterwards, had a few pints and moved on to the next chapter. I couldn't be mithered with it all anyway, you know what I mean? Can't be arsed.\\" — David King","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f5/IconPerks_noMither.png"},{"id":41,"name":"Sole Survivor","code":"solesurvivor","survivorCode":"lauriestrode","survivorName":"Laurie Strode","description":"As more of your friends fall to the Killer, you become shrouded in isolation and the Killer's Aura-reading abilities towards you are disrupted.\\nEach time a Survivor other than yourself is killed or sacrificed, Sole Survivor gains 1 Token, up to a maximum of 3 Tokens:\\nEach Token grants a stack-able radius of 20/22/24 metres within which the Killer is unable to read your Aura, up to a maximum of 60/66/72 metres.\\nOnce you are the last Survivor standing, you benefit from the following effects:\\nIncreases the Repair speed of Generators by +75 %.\\nIncreases the Opening speed of Exit Gates and the Hatch by +50 %.\\n\\"It was the boogeyman.\\" — Laurie Strode","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8e/IconPerks_soleSurvivor.png"},{"id":42,"name":"Object of Obsession","code":"objectofobsession","survivorCode":"lauriestrode","survivorName":"Laurie Strode","description":"A supernatural bond links you to the Killer.\\nWhenever the Killer reads your Aura and for the same duration as they do so, Object of Obsession activates:\\nThe Killer's Aura is revealed to you.\\nIncreases your Action speeds in Repairing, Healing, and Cleansing by 2/4/6%.\\nIf you are the Obsession, your Aura is automatically revealed to the Killer for 3 seconds every 30 seconds.\\nIncreases the odds of becoming the Killer's initial Obsession by 100%.\\nThe Killer can only be obsessed with one Survivor at a time.\\n\\"He was watching me!\\" — Laurie Strode","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2b/IconPerks_objectOfObsession.png"},{"id":43,"name":"Decisive Strike","code":"decisivestrike","survivorCode":"lauriestrode","survivorName":"Laurie Strode","description":"Using whatever is at hand, you stab at your aggressor in an ultimate attempt to escape.\\nAfter being unhooked or unhooking yourself, Decisive Strike will become active and usable for 40/50/60 seconds.\\nWhile Decisive Strike is active, when grabbed by the Killer, succeed a Skill Check to automatically escape the Killer's grasp and stun the Killer for 3 seconds.\\nSuccessfully stunning the Killer will result in you becoming the Obsession.\\nWhile Decisive Strike is active, performing Conspicuous Actions will deactivate it for the remainder of the Trial.\\nDecisive Strike deactivates once the Exit Gates are powered.\\nIncreases the odds of being the Obsession.\\nThe Killer can only be obsessed with one Survivor at a time.\\n\\"There is nothing to be scared of.\\" — Laurie Strode","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ee/IconPerks_decisiveStrike.png"},{"id":44,"name":"Open-Handed","code":"openhanded","survivorCode":"acevisconti","survivorName":"Ace Visconti","description":"Strengthens the potential in your and your team's Aura-reading abilities.\\nOpen-Handed increases all Aura-reading ranges by 8/12/16 meters.\\nOpen-Handed does not stack with other instances of itself.\\n\\"Paying attention is what kept me alive through the years. That, and my good looks of course.\\" — Ace Visconti","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_open-Handed.png"},{"id":45,"name":"Up the Ante","code":"uptheante","survivorCode":"acevisconti","survivorName":"Ace Visconti","description":"All will be well in the end; you just know it.\\nYour confidence strengthens the feeling of hope for those around you.\\nFor Each Survivor still in the Trial, Up the Ante gains 1 Token.\\nEach Token applies a stack-able 1/2/3% bonus to the Luck of all Survivors, up to a maximum of 3/6/9%.\\n\\"What can I say? I'm just a very lucky guy... I'm sure some of it will rub off on you.\\" — Ace Visconti","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a3/IconPerks_upTheAnte.png"},{"id":46,"name":"Ace in the Hole","code":"aceinthehole","survivorCode":"acevisconti","survivorName":"Ace Visconti","description":"Lady Luck always seems to be throwing something good your way.\\nWhen retrieving an Item from a Chest, there is a chance an Add-on will be attached to it.\\n100% chance for an Add-on of Very Rare Rarity or lower.\\n10/25/50% chance for a second Add-on of Uncommon Rarity or lower.\\nAce in the Hole allows you to keep any Add-ons your Item has equipped upon escaping.\\n\\"Everything that glitters isn't gold. But gold isn't worth a damn in this place, so this should come in handy.\\" — Ace Visconti","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconPerks_aceInTheHole.png"},{"id":47,"name":"Technician","code":"technician","survivorCode":"fengmin","survivorName":"Feng Min","description":"You are apt at handling machinery with the greatest care and precision.\\nFailing a Skill Check while repairing:\\nPrevents the Generator Explosion.\\nApplies the default Regression penalty.\\nApplies an additional Regression penalty of 5/4/3%.\\nTechnician reduces the audible range of your Generator-repairing noises by 8 meters.\\n\\"I am gonna stealth this one.\\" — Feng Min","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/62/IconPerks_technician.png"},{"id":48,"name":"Lithe","code":"lithe","survivorCode":"fengmin","survivorName":"Feng Min","description":"After performing a rushed vault, break into a sprint of 150% of your normal Running Movement speed for a maximum of 3 seconds.\\nLithe causes the Exhausted Status Effect for 60/50/40 seconds.\\nLithe cannot be used when Exhausted.\\n\\"U mad?\\" — Feng Min","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconPerks_lithe.png"},{"id":49,"name":"Alert","code":"alert","survivorCode":"fengmin","survivorName":"Feng Min","description":"Your acute senses are on high alert.\\nWhenever the Killer destroys a Pallet or a Breakable Wall, or damages a Generator, their Aura is revealed to you for 3/4/5 seconds.\\n\\"I have true sight,\\" — Feng Min","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/71/IconPerks_alert.png"},{"id":50,"name":"Wake Up!","code":"wakeup","survivorCode":"quentinsmith","survivorName":"Quentin Smith","description":"Unlocks potential in your Aura-reading ability.\\nOnce all Generators are completed, Wake Up! activates:\\nThe Auras of the Exit Gate Switches are revealed to you within 128 meters.\\nWhen opening an Exit Gate, your Aura is revealed to all other Survivors within 128 meters.\\nYou open Exit Gates 15/20/25% faster.\\n\\"Ok, look. If we survive the next 24 hours, then I'll take you out on a real date.\\" — Quentin Smith","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fd/IconPerks_wakeUp.png"},{"id":51,"name":"Pharmacy","code":"pharmacy","survivorCode":"quentinsmith","survivorName":"Quentin Smith","description":"You have a knack for finding medicine.\\nSearches through Chests are 40/60/80 % faster and the noises they cause along with their hearing distances are reduce by 8 metres.\\nPharmacy guarantees an Emergency Med-Kit each time you unlock a Chest while in the Injured State.\\n\\"Adrenaline, it is going to keep us awake. I stole it from one of the Nurse's carts.\\" — Quentin Smith","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f1/IconPerks_pharmacy.png"},{"id":52,"name":"Vigil","code":"vigil","survivorCode":"quentinsmith","survivorName":"Quentin Smith","description":"You look over your friends even in dire situations.\\nIncreases your Recovery rate from the Blindness, Broken, Exhaustion, Exposed, Haemorrhage, Hindered, and Oblivious Status Effects by 20/25/30%.\\nThis effect also applies to all other Survivors within 8 meters of your location and lingers for 15 seconds.\\n\\"I am gonna be here when you wake up. You are gonna make it.\\" — Quentin Smith","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/46/IconPerks_vigil.png"},{"id":53,"name":"Tenacity","code":"tenacity","survivorCode":"davidtapp","survivorName":"David Tapp","description":"There is nothing stopping you.\\nYour ferocious tenacity in dire situations allows you to crawl 30/40/50 % faster and also recover at the same time.\\nReduces the volume of Grunts of Pain while in the Dying State by -75 %.\\n\\"What the hell is this? I'm taking this bastard down!\\" — Detective David Tapp","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9d/IconPerks_tenacity.png"},{"id":54,"name":"Detective's Hunch","code":"detectiveshunch","survivorCode":"davidtapp","survivorName":"David Tapp","description":"Unlocks potential in your Aura-reading ability.\\nEach time a Generator is completed, the Auras of any Generators, Chests, and Totems within 32/48/64 meters are revealed to you for 10 seconds.\\nIf you are holding a Map, any objects revealed by Detective's Hunch will automatically be tracked by it.\\n\\"Are you able to tell us where you were last night?\\" — Detective David Tapp","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7b/IconPerks_detectivesHunch.png"},{"id":55,"name":"Stake Out","code":"stakeout","survivorCode":"davidtapp","survivorName":"David Tapp","description":"Getting close to the Killer fills you with determination.\\nEvery 15 seconds you are standing within the Killer's Terror Radius without being chased, Stake Out gains 1 Token, up to a maximum of 2/3/4 Tokens.\\nWhen Stake Out has at least 1 Token, Good Skill Checks consume 1 Token and are considered Great Skill Checks, granting an additional Progression bonus of 1%.\\nGreat Skill Checks do not consume any Tokens.\\n\\"I had you, I had you on your knees. You're runnin' scared because we had you. We're gonna close this case!\\" — Detective David Tapp","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cd/IconPerks_stakeOut.png"},{"id":56,"name":"Dance With Me","code":"dancewithme","survivorCode":"katedenson","survivorName":"Kate Denson","description":"When performing a rushed action to vault a Window, Pallet, or leave a Locker, you will not leave any Scratch Marks for the next 3 seconds.\\nDance With Me has a cool-down of 60/50/40 seconds.\\n\\"Another show's off and runnin',\\nDance with me, cuz there's a storm a commin'\\nFollow my boots, try to keep up,\\nDance with me, until sun up.\\" — Kate Denson's \\"Dance with Me\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/17/IconPerks_danceWithMe.png"},{"id":57,"name":"Windows of Opportunity","code":"windowsofopportunity","survivorCode":"katedenson","survivorName":"Kate Denson","description":"Unlocks potential in your Aura-reading ability.\\nThe Auras of Breakable Walls, Pallets, and Windows are revealed to you within 24/28/32 meters.\\n\\"Rise and shine, work hard, carve out your name,\\nTake aim, pull the trigger, hit the bulls eye for fame,\\nKnow the value of faith, an' family, and don't you complain,\\nOpen wide, your windows of opportunity\\" — Kate Denson's \\"Windows of Opportunity\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/17/IconPerks_windowsOfOpportunity.png"},{"id":58,"name":"Boil Over","code":"boilover","survivorCode":"katedenson","survivorName":"Kate Denson","description":"You are a battler and do everything to escape a foe's grasp.\\nWhile being carried by the Killer, the following effects apply:\\nIncreases the intensity of the Struggle Effects on the Killer from your Wiggling by 60/70/80 %.\\nObscures the Auras of all Hooks from the Killer's Aura-reading abilities within 16 meters.\\nFills your Wiggle Meter by 33% of your current Wiggle progression upon landing, when the Killer drops from great heights.\\n\\"Buck and Wild,\\nSwing to be free,\\nYour hands just can't keep ahold of me.\\" — Kate Denson's \\"Boil Over\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f5/IconPerks_boilOver.png"},{"id":59,"name":"Diversion","code":"diversion","survivorCode":"adamfrancis","survivorName":"Adam Francis","description":"Activate-able perk.\\nStanding within the Killer's Terror Radius while not in a Chase for 40/35/30 seconds activates Diversion.\\nOnce Diversion is activated, press the Active Ability button while crouched and motionless to throw a pebble, creating a distraction for the Killer at a distance of 20 meters.\\nThe distraction consists of the following:\\nA Loud Noise Notification.\\nScratch Marks.\\nDiversion's timer resets once the ability has been activated.\\n\\"There's what is easy and then there's what is right. If you confuse the two, there's no telling what you become.\\" — Adam Francis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a6/IconPerks_diversion.png"},{"id":60,"name":"Deliverance","code":"deliverance","survivorCode":"adamfrancis","survivorName":"Adam Francis","description":"After performing a Safe Hook Rescue on another Survivor, Deliverance activates:\\nYour Self-Unhook attempts will succeed 100% of the time.\\nDeliverance causes the Broken Status Effect for 100/80/60 seconds after unhooking yourself.\\n\\"I was raised by a strict man who taught me how to make the best of a bad situation.\\" — Adam Francis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7e/IconPerks_deliverance.png"},{"id":61,"name":"Autodidact","code":"autodidact","survivorCode":"adamfrancis","survivorName":"Adam Francis","description":"You start the Trial with a 25% Progression penalty for Skill Checks to heal Survivors.\\nFor every successful Skill Check completed while healing a Survivor, Autodidact gains 1 Token up to a maximum of 3/4/5 Tokens.\\nEach Token grants a 15% bonus Progression for a successful Skill Check while healing Survivors.\\nGreat Skill Checks cannot be performed while using Autodidact.\\nAutodidact is not active when using a Med-Kit to heal.\\n\\"There's no limit to what you can achieve, as long as you back with hard work.\\" — Adam Francis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/96/IconPerks_autodidact.png"},{"id":62,"name":"Breakdown","code":"breakdown","survivorCode":"jeffjohansen","survivorName":"Jeff Johansen","description":"Each time you are unhooked or unhook yourself, the Hook breaks and the Killer's Aura is revealed to you for 4/5/6 seconds.\\nA Hook broken by Breakdown takes 180 seconds to respawn.\\n\\"Charge from the Belly of the Beast.\\nHere's a sketch/painting on a piece of wood I saw by the side of this road. I felt like it got a story to tell. And it didn't waste its second chance.\\" — Jeff, ink and oil wash on slice of wood, 12x16","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6c/IconPerks_breakdown.png"},{"id":63,"name":"Aftercare","code":"aftercare","survivorCode":"jeffjohansen","survivorName":"Jeff Johansen","description":"Unlocks potential in your Aura-reading ability.\\nYou see the Aura of the last 1/2/3 Survivor(s):\\nYou have rescued from a Hook, or who have rescued you from a Hook.\\nYou have completed a Healing action on, or who have completed a Healing action on you.\\nThey also see your Aura.\\nAll effects of Aftercare are reset upon being hooked by the Killer.\\n\\"A Mercy that Rips the Storm.\\nOil work to honour my best buddies who happen to be the best musicians I know. Their first album is still my favourite. It got me through a dark time in my life.\\" — Jeff, oil on canvas, 16x16","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0d/IconPerks_aftercare.png"},{"id":64,"name":"Distortion","code":"distortion","survivorCode":"jeffjohansen","survivorName":"Jeff Johansen","description":"You start the Trial with 3 Tokens.\\nWhenever the Killer attempts to read your Aura, Distortion activates and 1 Token is consumed:\\nYour Aura will not be shown to the Killer and you will not leave any Scratch Marks for the next 6/8/10 seconds.\\nEvery 30 seconds you are within the Killer's Terror Radius, Distortion gains back 1 Token.\\nDistortion does not activate when you are in the Dying State.\\n\\"Death Fooled by the Cloak of Falcon Feathers.\\nSketch inspired by a few sleepless nights during winter. Exploration of Norse mythology: bravery can conceal your flaws, even when you are at your most vulnerable.\\" — Jeff, pencil on tone paper, 12x12","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/41/IconPerks_distortion.png"},{"id":65,"name":"Solidarity","code":"solidarity","survivorCode":"janeromero","survivorName":"janeromero","description":"Sharing painful experiences has the power to heal.\\nWhen injured, healing another Survivor without using a Med-Kit also heals you with a Conversion rate of 40/45/50%.\\n\\"Showing up when things get rough, listening to people's problems, and supporting those in need; that's how you become stronger, that's how you grow.\\" — Jane Romero","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconPerks_solidarity.png"},{"id":66,"name":"Poised","code":"poised","survivorCode":"janeromero","survivorName":"janeromero","description":"Achieving goals boosts your confidence.\\nAfter a GeneratorIcon is completed, you will not leave any Scratch Marks for the next 6/8/10 seconds.\\n\\"Ok, stay calm. Don't overthink it and just keep moving forward: you got this.\\" — Jane Romero","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_poised.png"},{"id":67,"name":"Head On","code":"headon","survivorCode":"janeromero","survivorName":"janeromero","description":"When your mind is set, there better be no one standing in your way.\\nWhile standing in a Locker for 3 seconds, Head On activates:\\nWhen performing a rushed action to leave a Locker, stun the Killer for 3 seconds if they are within range.\\nHead On causes the Exhausted Status Effect for 60/50/40 seconds.\\nHead On cannot be used when Exhausted or when you have accrued Stillness Crows.\\n\\"People are remembered for the challenges they overcome. You can run away and forget what you're capable of or you can face your fears and remind the world of who you are.\\" — Jane Romero","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cb/IconPerks_headOn.png"},{"id":68,"name":"Flip-Flop","code":"flipflop","survivorCode":"ashjwilliams","survivorName":"Ash J. Williams","description":"You have an uncanny ability to escape the inevitable.\\nWhile in the Dying State, 50% of your Recovery progression is converted into Wiggling progression, up to a maximum of 40/45/50%, once you are picked up by the Killer.\\n\\"Catch ya on the flip-flop.\\" — Ash Williams","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_flip-Flop.png"},{"id":69,"name":"Buckle Up","code":"buckleup","survivorCode":"ashjwilliams","survivorName":"Ash J. Williams","description":"Unlocks potential in your Aura-reading ability.\\nYou can determine the Recovery progress of dying Survivors by the intensity of their Aura at a distance of 48 meters away.\\nWhen healing another Survivor from the Dying State to the Injured State, the Killer's Aura is revealed to the both of you for 6/8/10 seconds.\\n\\"Ghost beaters never leave a man behind.\\" — Ash Williams","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/74/IconPerks_buckleUp.png"},{"id":70,"name":"Mettle of Man","code":"mettleofman","survivorCode":"ashjwilliams","survivorName":"Ash J. Williams","description":"Evil has a way of always finding you.\\nAfter you earn 3 Protection Hit Score Events, Mettle of Man activates.\\nOnce activated, the next occasion that would put you into the Dying State from the Injured State is ignored.\\nThe next time you heal back to full health, your Aura will be revealed to the Killer when you are farther than 12/14/16 metres from the Killer.\\nMettle of Man will deactivate the next time you are put into the Dying State.\\nIncreases your chances of being the Obsession.\\nThe Killer can only be obsessed with one Survivor at a time.\\n\\"Evil has a bullseye on my back the size of Tiger Stadium.\\" — Ash Williams","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_mettleOfMan.png"},{"id":71,"name":"Lucky Break","code":"luckybreak","survivorCode":"yuikimura","survivorName":"Yui Kimura","description":"You have had your share of scrapes and bruises, but luck is always on your side.\\nWhenever you are in the Injured State, Lucky Break activates:\\nBleeding and Scratch Marks are suppressed for a maximum of 40/50/60 seconds, after which Lucky Break deactivates.\\nEach second spent healing other Survivors recharges Lucky Break up to the maximum Effect duration at a Conversion rate of 100 %.\\nLucky Break deactivates when you are Healthy or in the Dying State.\\n\\"That's not enough to beat me. Not even close.\\" — Yui Kimura","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a7/IconPerks_luckyBreak.png"},{"id":72,"name":"Any Means Necessary","code":"anymeansnecessary","survivorCode":"yuikimura","survivorName":"Yui Kimura","description":"You stand up for yourself, using whatever's on hand to gain an advantage.\\nYou see the Auras of dropped Pallets.\\nPress and hold the Active Ability button for 4 seconds while standing beside a dropped Pallet to reset it to its upright position.\\nAny Means Necessary has a cool-down of 100/80/60 seconds.\\n\\"I'll hit you with everything I've got. Then I'll do it again.\\" — Yui Kimura","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/79/IconPerks_anyMeansNecessary.png"},{"id":73,"name":"Breakout","code":"breakout","survivorCode":"yuikimura","survivorName":"Yui Kimura","description":"You kick into high gear when someone is in trouble, inspiring them to overcome any obstacle.\\nWhen within 6 meters of a carried Survivor, you gain the Haste Status Effect, moving at an increased speed of 5/6/7%.\\nThe carried Survivor's Wiggling speed is increased by 20%.\\n\\"Come, we're going to rip our way out of this.\\" — Yui Kimura","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d0/IconPerks_breakout.png"},{"id":74,"name":"Off the Record","code":"offtherecord","survivorCode":"zarinakassir","survivorName":"Zarina Kassir","description":"You have learnt that a quiet approach is sometimes best.\\nAfter being unhooked or unhooking yourself, Off the Record activates for the next 60/70/80 seconds:\\nYour Aura will not be shown to the Killer if they attempt to read it.\\nWhen injured, Grunts of Pain are reduced by 100 %.\\nGrants the Endurance Status Effect.\\nThis effect is cancelled prematurely if you perform a Conspicuous Action.\\nOff the Record deactivates once the Exit Gates are powered.\\n\\"Trust me, I investigate thoroughly and discreetly.\\" — Zarina Kassir","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconPerks_offTheRecord.png"},{"id":75,"name":"Red Herring","code":"redherring","survivorCode":"zarinakassir","survivorName":"Zarina Kassir","description":"You have noticed that people pay attention to whatever makes the loudest noise.\\nAfter repairing a Generator for at least 3 seconds, its Aura is highlighted to you in yellow.\\nThe Generator stays highlighted until it is either fully repaired, you start repairing another Generator, or enter a Locker.\\nEntering a Locker will trigger a Loud Noise Notification for the Killer at the highlighted Generator's location.\\nRed Herring has a cool-down of 60/50/40 seconds.\\n\\"The news edit out what is burdensome and complex. which is the truth.\\" — Zarina Kassir","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_redHerring.png"},{"id":76,"name":"For the People","code":"forthepeople","survivorCode":"zarinakassir","survivorName":"Zarina Kassir","description":"You risk life and injury for others.\\nFor the People is only active while at full health.\\nPress the Active Ability button while healing another Survivor without a Med-Kit to instantly heal them 1 Health State.\\nYou become the Obsession.\\nFor the People causes the Broken Status Effect for 80/70/60 seconds after using it.\\nLowers the odds of becoming the Killer's initial Obsession by 100%.\\nThe Killer can only be obsessed with one Survivor at a time.\\n\\"We can write our own story and decide how it really ends.\\" — Zarina Kassir","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_forThePeople.png"},{"id":77,"name":"Soul Guard","code":"soulguard","survivorCode":"cherylmason","survivorName":"Cheryl Mason","description":"You have been through immense hardship and you're stronger for it.\\nAfter being healed from or having recovered from the Dying State, Soul Guard grants you the Endurance Status Effect for the next 4/6/8 seconds.\\nAny damage taken that would put you into the Dying State will instead trigger the Deep Wound Status Effect, after which you have 20 seconds to Mend yourself.\\nTaking any damage while under the effect of Deep Wound or if its timer runs out will put you into the Dying State.\\nSoul Guard allows you to completely recover from the Dying State when you are affected by the Cursed Status Effect.\\nSoul Guard has a cool-down of 30 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a5/IconPerks_soulGuard.png"},{"id":78,"name":"Blood Pact","code":"bloodpact","survivorCode":"cherylmason","survivorName":"Cheryl Mason","description":"It is as if a latent part of yourself has awakened.\\nYou feel like you can reach out beyond yourself for assistance.\\nWhen you or the Obsession are injured, you both see each other's Auras.\\nAfter healing the Obsession or being healed by the Obsession, you both gain the Haste Status Effect, moving at an increased speed of 5/6/7% until you are no longer within 16 meters of each other.\\nIf you are the Obsession, Blood Pact deactivates.\\nLowers the odds of becoming the Killer's initial Obsession by 100%.\\nThe Killer can only be obsessed with one Survivor at a time.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c9/IconPerks_bloodPact.png"},{"id":79,"name":"Repressed Alliance","code":"repressedalliance","survivorCode":"cherylmason","survivorName":"Cheryl Mason","description":"You are accustomed to being hunted by malicious forces, and you have begun using it to your advantage.\\nAfter repairing Generators for a total of 55/50/45 seconds, Repressed Alliance activates:\\nPress the Active Ability button to call upon The Entity to block the Generator you are currently repairing for 30 seconds, after which Repressed Alliance deactivates.\\nThe Aura of the blocked Generator is revealed to all Survivors in white.\\nRepressed Alliance can only be triggered when no other Survivors are repairing your Generator.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_repressedAlliance.png"},{"id":80,"name":"Visionary","code":"visionary","survivorCode":"felixrichter","survivorName":"Felix Richter","description":"You are remarkably focused on your means of escape.\\nThe Auras of Generators are revealed to you within 32 meters.\\nEach time a Generator is completed, Visionary is disabled for 20/18/16 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7c/IconPerks_visionary.png"},{"id":81,"name":"Desperate Measures","code":"desperatemeasures","survivorCode":"felixrichter","survivorName":"Felix Richter","description":"You refuse to fail, even during your darkest hour.\\nIncreases Healing and Unhooking speeds by 10/12/14 % for each injured, hooked, or dying Survivor, up to a maximum of 40/48/56 %.\\n\\"When they come with a wrecking ball, build stronger walls.\\" — Felix Richter","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/84/IconPerks_desperateMeasures.png"},{"id":82,"name":"Built to Last","code":"builttolast","survivorCode":"felixrichter","survivorName":"Felix Richter","description":"You know how to get the most out of your tools.\\nHiding inside a Locker for 14/13/12 seconds while carrying a depleted Item will replenish its Charges to 99 %.\\nEach use of Built to Last reduces this percentage by 33%.\\n\\"Architecture is the soul of civilisation.\\" — Felix Richter","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_builtToLast.png"},{"id":83,"name":"Appraisal","code":"appraisal","survivorCode":"elodierakoto","survivorName":"Élodie Rakoto","description":"You have a careful eye that notices what many overlook.\\nStart the Trial with 3 Tokens:\\nWhen a Chest has already been opened, consume 1 Token to rummage through it for an Item.\\nRummage through Chests 40/60/80% faster.\\nRummaging is only available once per Chest.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c1/IconPerks_appraisal.png"},{"id":84,"name":"Deception","code":"deception","survivorCode":"elodierakoto","survivorName":"Élodie Rakoto","description":"Your adventurous lifestyle requires moments of crafty misdirection.\\nInteract with a Locker while holding the Sprint button to trigger a Loud Noise Notification for the killer at your location instead of entering the Locker.\\nYou will not leave any Scratch Marks or Pools of Blood for the next 3 seconds.\\nDeception can only be triggered once every 60/50/40 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_deception.png"},{"id":85,"name":"Power Struggle","code":"powerstruggle","survivorCode":"elodierakoto","survivorName":"Élodie Rakoto","description":"You have never given up and you are not about to start now.\\nReveals the Auras of available Pallets whenever you are in the Dying State.\\nWhile being carried by The Killer, reaching 25/20/15% Wiggling progression activates Power Struggle:\\nYou can drop a nearby, standing Pallet to stun the Killer and escape their grasp.\\nPower Struggle deactivates after triggering successfully.\\n\\"I relied on others to protect me once and I lost everything. Never again.\\" — Élodie Rakoto","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconPerks_powerStruggle.png"},{"id":86,"name":"Fast Track","code":"fasttrack","survivorCode":"yunjinlee","survivorName":"Yun-Jin Lee","description":"Sometimes the sacrifice of others is necessary to get ahead.\\nWhenever another Survivor is hooked, Fast Track gains 1/2/3 Tokens, up to a maximum of 9/18/27 Tokens.\\nYou consume all accumulated Tokens after a Great Skill Check on a Generator.\\nEach Token grants a stack-able 1% Progression bonus in addition to the default Progression bonus for succeeding a Great Skill Check.\\n\\"The weak are sacrificed first. It's nature, it's business... it's the truth most refuse to face.\\" — Yun-Jin Lee","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/75/IconPerks_fastTrack.png"},{"id":87,"name":"Smash Hit","code":"smashhit","survivorCode":"yunjinlee","survivorName":"Yun-Jin Lee","description":"When your rival makes a mistake, you seize the opportunity.\\nAfter stunning the Killer with a Pallet, break into a sprint at 150% of your normal Running Movement speed for 4 seconds.\\nSmash Hit causes the Exhausted Status Effect for 60/50/40 seconds.\\nSmash Hit cannot be used when Exhausted.\\n\\"I have dealt with psychopaths in suits. You're just uglier and worse dressed.\\" — Yun-Jin Lee","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconPerks_smashHit.png"},{"id":88,"name":"Self-Preservation","code":"selfpreservation","survivorCode":"yunjinlee","survivorName":"Yun-Jin Lee","description":"Life is unforgiving.\\nThe more confirmation you get of that, the more prepared you become.\\nWhenever another Survivor is hit with a Basic Attack or Special Attack within 16 meters of you, Self-Preservation activates:\\nScratch Marks, Grunts of Pain when injured, and Bleeding are suppressed for the next 6/8/10 seconds.\\n\\"Something I learnt in the industry: when the axe is swinging, keep your head down.\\" — Yun-Jin Lee","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/43/IconPerks_self-Preservation.png"},{"id":89,"name":"Counterforce","code":"counterforce","survivorCode":"jillvalentine","survivorName":"Jill Valentine","description":"You know how to withstand an enemy stronger than you, and it starts with hunting down and knocking out their support.\\nYou cleanse Totems 20 % faster.\\nGain another, stack-able 20% Cleansing Speed bonus per cleansed Totem.\\nAfter cleansing a Totem, the Aura of the Totem farthest from you is revealed to you for 2/3/4 seconds.\\n\\"I don't mind a little detective work.\\" — Jill Valentine","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconPerks_counterforce.png"},{"id":90,"name":"Resurgence","code":"resurgence","survivorCode":"jillvalentine","survivorName":"Jill Valentine","description":"You have come back from near impossible odds... and you will do it again.\\nAfter being unhooked or unhooking yourself, instantly gain 40/45/50% to your Healing progress.\\n\\"It's my turn, bitch!\\" — Jill Valentine","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f3/IconPerks_resurgence.png"},{"id":91,"name":"Blast Mine","code":"blastmine","survivorCode":"jillvalentine","survivorName":"Jill Valentine","description":"When direct combat is not an option, you still find ways to strike back.\\nAfter repairing Generators for a total of 50 %, Blast Mine activates:\\nAfter repairing a Generator for at least 3 seconds, press the Active Ability button to install a Trap, which stays active for 40/45/50 seconds.\\nThe Aura of Trapped Generators are revealed in yellow to all Survivors.\\nWhen the Killer damages a Trapped Generator, the Trap explodes, stunning them and blinding anyone nearby.\\nBlast Mine deactivates after triggering successfully or if the timer runs out.\\n\\"You want S.T.A.R.S.? I'll give you S.T.A.R.S.!\\" — Jill Valentine","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_blastMine.png"},{"id":92,"name":"Bite the Bullet","code":"bitethebullet","survivorCode":"leonscottkennedy","survivorName":"Leon Scott Kennedy","description":"Pain hurts you as much as anyone, but you would prefer others do not know that.\\nWhen healing yourself or another Survivor, Grunts of Pain and all noises related to the Healing action are suppressed:\\nFailed Healing Skill Checks do not trigger a Loud Noise Notification and only apply a Regression penalty of 3/2/1 %.\\n\\"I can do this.\\" — Leon Scott Kennedy","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a5/IconPerks_biteTheBullet.png"},{"id":93,"name":"Flashbang","code":"flashbang","survivorCode":"leonscottkennedy","survivorName":"Leon Scott Kennedy","description":"You have adapted to a world in chaos and making what you can from the debris.\\nAfter repairing Generators for a total of 70/60/50%, Flashbang activates:\\nEnter a Locker while empty-handed and press the Ability button to craft a Flash Grenade.\\nThe Flashbang is left behind when escaping the Trial.\\n\\"Get outta my face!\\" — Leon Scott Kennedy","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/db/IconPerks_flashbang.png"},{"id":94,"name":"Rookie Spirit","code":"rookiespirit","survivorCode":"leonscottkennedy","survivorName":"Leon Scott Kennedy","description":"You keep a careful eye on objectives when they are slipping away.\\nWhile repairing Generators, complete 5/4/3 Good or Great Skill Checks to activate Rookie Spirit for the remainder of the Trial:\\nOnce active, the Auras of any regressing Generators are revealed to you.\\n\\"I'll stop this, lieutenant. I promise.\\" — Leon Scott Kennedy","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2f/IconPerks_rookieSpirit.png"},{"id":95,"name":"Clairvoyance","code":"clairvoyance","survivorCode":"mikaelareid","survivorName":"Mikaela Reid","description":"There is an intrinsic energy in you that sees beyond your vision.\\nWhenever you cleanse a Totem, Clairvoyance activates:\\nWhen empty-handed, press and hold the Ability button to unlock your full Aura-reading potential, allowing you to see the Auras of the Exit Gate Switches, Generators, Hooks, Chests, and the Hatch within 64 meters for 8/9/10 seconds.\\n\\"Does anyone else see that? Just me?\\" — Mikaela Reid","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/91/IconPerks_clairvoyance.png"},{"id":96,"name":"Boon: Circle of Healing","code":"booncircleofhealing","survivorCode":"mikaelareid","survivorName":"Mikaela Reid","description":"A Boon that offers comfort amidst the terror.\\nPress and hold the Active Ability button near a Dull or Hex Totem to bless it and create a Boon Totem.\\nSoft chimes ring out within a radius of 24 meters.\\nSurvivors inside the Boon Totem's range benefit from the following effects:\\n40/45/50% bonus to all Healing speeds.\\nUnlocks the Self-Care ability, allowing to self-heal without needing a Med-Kit.\\nReduces Personal Healing speed by 50%.\\nBenefits from the general Healing Speed bonus.\\nBoon: Circle of Healing does not stack with other instances of itself.\\nYou can only bless one Totem at a time.\\nAll equipped Boon Perks are active on the same Boon Totem.\\n\\"Try this, it is better than anything you'll find in a pharmacy.\\" — Mikaela Reid","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/54/IconPerks_boonCircleOfHealing.png"},{"id":97,"name":"Boon: Shadow Step","code":"boonshadowstep","survivorCode":"mikaelareid","survivorName":"Mikaela Reid","description":"A Boon that conceals the truth.\\nPress and hold the Active Ability button near a Dull or Hex Totem to bless it and create a Boon Totem.\\nSoft chimes ring out within a radius of 24 meters.\\nSurvivors inside the Boon Totem's range benefit from the following effects:\\nScratch Marks are suppressed.\\nAuras are hidden from The Killer.\\nBoth effects linger for 2/3/4 seconds after leaving the Boon Totem's range.\\nYou can only bless one Totem at a time.\\nAll equipped Boon Perks are active on the same Boon Totem.\\n\\"Stick to the shadows and cover your tracks.\\" — Mikaela Reid","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c7/IconPerks_boonShadowStep.png"},{"id":98,"name":"Overcome","code":"overcome","survivorCode":"jonahvasquez","survivorName":"Jonah Vasquez","description":"You have calculated how much energy you can risk to expend.\\nWhenever you become injured, you retain the Movement Speed burst for 2 additional seconds.\\nOvercome causes the Exhausted Status Effect for 60/50/40 seconds.\\nOvercome cannot be used when Exhausted.\\n\\"After careful analysis, we are getting the hell out of here!\\" — Jonah Vasquez","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/82/IconPerks_overcome.png"},{"id":99,"name":"Corrective Action","code":"correctiveaction","survivorCode":"jonahvasquez","survivorName":"Jonah Vasquez","description":"You quickly analyse problems and correct others' work when they make a mistake.\\nYou start the Trial with 1/2/3 Token(s) and gain a Token each time you succeed at a Great Skill Check, up to a maximum of 5 Tokens.\\nEach time another Survivor cooperating with you on the same Generator fails a Skill Check, Corrective Action consumes 1 Token, transforming their Failed Skill Check into Good Skill Check instead.\\nCorrective Action only applies to normal Skill Checks.\\n\\"Cannot hurt to have another set of eyes on the problem.\\" — Jonah Vasquez","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconPerks_correctiveAction.png"},{"id":100,"name":"Boon: Exponential","code":"boonexponential","survivorCode":"jonahvasquez","survivorName":"Jonah Vasquez","description":"When it seems like your number is up, you consider ways to recalculate the odds.\\nPress and hold the Active Ability button near a Dull or Hex Totem to bless it and create a Boon Totem.\\nSoft chimes ring out within a radius of 24 meters.\\nSurvivors inside the Boon Totem's range benefit from the following effects:\\n90/95/100% bonus to the Recovery speed.\\nUnlocks the Self-Recovery ability, allowing you to fully recover from the Dying State.\\nYou can only bless one Totem at a time.\\nAll equipped Boon Perks are active on the same Boon Totem.\\n\\"It is not our time to die... probably.\\" — Jonah Vasquez","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/76/IconPerks_boonExponential.png"},{"id":101,"name":"Parental Guidance","code":"parentalguidance","survivorCode":"yoichiasakawa","survivorName":"Yoichi Asakawa","description":"You have inherited the ability to hear the dead — and now the dead warn you of danger.\\nAfter stunning the Killer by any means, Parental Guidance suppresses your Scratch Marks, Pools of Blood, and Grunts of Pain for the next 5/6/7 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/46/IconPerks_parentalGuidance.png"},{"id":102,"name":"Empathic Connection","code":"empathicconnection","survivorCode":"yoichiasakawa","survivorName":"Yoichi Asakawa","description":"Your presence psychically projects itself to those in danger.\\nWhenever another Survivor is injured, they can see your Aura when within 32/64/96 meters of your location.\\nYou heal other Survivors 10% faster.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_empathicConnection.png"},{"id":103,"name":"Boon: Dark Theory","code":"boondarktheory","survivorCode":"yoichiasakawa","survivorName":"Yoichi Asakawa","description":"Your obsessive study of the paranormal has given you unprecedented knowledge of other Realms and planes of existence.\\nPress and hold the Active Ability button near a Dull or Hex Totem to bless it and create a Boon Totem.\\nSoft chimes ring out within a radius of 24 meters.\\nSurvivors inside the Boon Totem's range benefit from the following effects:\\n2% Haste Status Effect.\\nThis effect lingers for 2/3/4 seconds after leaving the Boon Totem's range.\\nYou can only bless one Totem at a time.\\nAll equipped Boon Perks are active on the same Boon Totem.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/60/IconPerks_boonDarkTheory.png"},{"id":104,"name":"Inner Focus","code":"innerfocus","survivorCode":"haddiekaur","survivorName":"Haddie Kaur","description":"You're able to concentrate and enter a meditative-like state to numb some pain.\\nGrunts of Pain caused by injuries are reduced by 25/50/75 %.\\nIron Will cannot be used when Exhausted.\\n\\"The death, the trauma, the fear... it all leads here. The Overlap.\\" — Haddie Kaur, Ravages of the Abyss Episode 11","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7e/IconPerks_innerFocus.png"},{"id":105,"name":"Residual Manifest","code":"residualmanifest","survivorCode":"haddiekaur","survivorName":"Haddie Kaur","description":"A lifetime of chasing the darkness has taught you that the best disinfectant is light.\\nAfter a successful Killer Blind, the Killer suffers from the Blindness Status Effect for 20/25/30 seconds.\\nResidual Manifest grants the ability to rummage through an opened Chest once per Trial and will guarantee a basic Flashlight.\\n\\"I'll never see what Haddie sees. But so long as I'm with her, I know I'm safe.\\" — Jordan Rois, Ravages of the Abyss Episode 5","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d0/IconPerks_residualManifest.png"},{"id":106,"name":"Overzealous","code":"overzealous","survivorCode":"haddiekaur","survivorName":"Haddie Kaur","description":"Fighting back against the Ravage motivates and inspires you.\\nAfter cleansing a Totem, Overzealous activates:\\nIncreases your Repair speed by 6/7/8 % if it was a Dull Totem.\\nIncreases your Repair speed by 12/14/16 % if it was a Hex Totem.\\nOverzealous deactivates when losing a Health State by any means.\\n\\"The Ravage senses us. We need to work fast.\\" — Haddie Kaur, Ravages of the Abyss Episode 9","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/99/IconPerks_overzealous.png"},{"id":107,"name":"Wiretap","code":"wiretap","survivorCode":"adawong","survivorName":"Ada Wong","description":"You know that the best way to stay one step ahead is to keep tabs on the competition.\\nAfter repairing Generators for a total of 33 %, Wiretap activates:\\nAfter repairing a Generator for 3 seconds, press the Active Ability button to install a Wiretap, which stays active for 60/70/80 seconds.\\nThe Auras of trapped Generators are revealed to all Survivors in yellow.\\nWhen the Killer comes within 14 metres of a trapped Generator, their Aura is revealed to all Survivors.\\nDamaging the Generator destroys the Wiretap.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/23/IconPerks_wiretap.png"},{"id":108,"name":"Reactive Healing","code":"reactivehealing","survivorCode":"adawong","survivorName":"Ada Wong","description":"The more the situation becomes compromised, the more determined you become to complete the operation.\\nWhen another Survivor loses a Health State within 32 metres of your location while you are in the Injured State, you benefit from the following effect:\\nGrants 40/45/50 % of your missing Healing Progression to your Health Bar.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_reactiveHealing.png"},{"id":109,"name":"Low Profile","code":"lowprofile","survivorCode":"adawong","survivorName":"Ada Wong","description":"You work best alone.\\nWhen it is just you and your pursuer, you know how to disappear.\\nWhenever you are the only Survivor in the Trial, who is not either in the Dying State, hooked, or already dead, Low Profile activates:\\nSuppresses your Pools of Blood, Scratch Marks, and Grunts of Pain for 70/80/90 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fb/IconPerks_lowProfile.png"},{"id":110,"name":"Better than New","code":"betterthannew","survivorCode":"rebeccachambers","survivorName":"Rebecca Chambers","description":"You are an expert in combat medicine.\\nPatients leave your care reinvigorated.\\nUpon completing a Healing action on another Survivor, they benefit from the following effect until the next time they take damage:\\nIncreases their Action speeds in Healing, Unlocking, Cleansing, and Blessing by 12/14/16 %.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b1/IconPerks_betterThanNew.png"},{"id":111,"name":"Reassurance","code":"reassurance","survivorCode":"rebeccachambers","survivorName":"Rebecca Chambers","description":"Your presence helps allies focus, assuaging the panic associated with extreme conditions.\\nWhen within 6 metres of a hooked Survivor, press the Active Ability button to halt their Sacrifice Process for the next 20/25/30 seconds.\\nIf the hooked Survivor has already entered the Struggle Phase, its Skill Checks are paused for that duration.\\nReassurance can only be used once per Survivor per Hook Instance.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5b/IconPerks_reassurance.png"},{"id":112,"name":"Hyperfocus","code":"hyperfocus","survivorCode":"rebeccachambers","survivorName":"Rebecca Chambers","description":"You throw yourself entirely into your tasks and find ways to be more efficient than anyone else.\\nAfter hitting a Great Skill Check while repairing or healing, Hyperfocus gains 1 Token, up to a maximum of 6 Tokens\\nFor each Token, the following stack-able effects are applied:\\nIncreases the Skill Check Trigger odds by +4 % per Token.\\nIncreases the Skill Check Rotation speed by +4 % per Token.\\nIncreases the Skill Check Bonus progression by 10/20/30 % of its base value per Token.\\nHyperfocus loses all Tokens when succeeding a Good Skill Check, failing a Skill Check, or if the action is interrupted by any means.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_hyperfocus.png"},{"id":113,"name":"Potential Energy","code":"potentialenergy","survivorCode":"vittoriotoscano","survivorName":"Vittorio Toscano","description":"Your arcane abilities have adapted to The Entity's Realm after centuries of wandering, granting you unprecedented control over its many devices.\\nAfter repairing Generators for a total of 12/10/8 uninterrupted seconds , press the Active Ability button to activate Potential Energy:\\nContinuing to repair the Generator will charge Potential Energy instead of progressing the Generator.\\nConverts 1.5 % of Repair progression into 1 Token, up to a maximum of 20 Tokens.\\nMissing Skill Checks results in losing some Tokens.\\nWhile Potential Energy has at least 1 Token, press the Active Ability button while repairing a Generator to instantly progress it by 1 % per Token, consuming all remaining Tokens and deactivating Potential Energy.\\nPotential Energy loses all Tokens and deactivates upon losing a Health State.\\n\\"When you look a layer deeper, you realise... everything is connected.\\" — Vittorio Toscano","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/07/IconPerks_potentialEnergy.png"},{"id":114,"name":"Fogwise","code":"fogwise","survivorCode":"vittoriotoscano","survivorName":"Vittorio Toscano","description":"In your countless years in The Fog, you have seen it all, and when you are focused, you can remember most of it too.\\nSucceeding a Great Skill Check while repairing a Generator reveals the Killer's Aura to you for 4/5/6 seconds.\\n\\"I have seen great cruelty... and I have also seen another way.\\" — Vittorio Toscano","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/90/IconPerks_fogwise.png"},{"id":115,"name":"Quick Gambit","code":"quickgambit","survivorCode":"vittoriotoscano","survivorName":"Vittorio Toscano","description":"When you have the Killer's attention, you know how to keep it; others can be confident they will not be interrupted any time soon.\\nIncreases the Repair speed of any other Survivor by 6/7/8 %, while you are being chased within 24 metres of the Generator they are currently repairing.\\n\\"We need not resort to violence. And I shall prove it.\\" — Vittorio Toscano","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconPerks_quickGambit.png"},{"id":116,"name":"Wicked","code":"wicked","survivorCode":"sableward","survivorName":"Sable Ward","description":"You have a... particular interest in the macabre. When you are in the Basement, you see the Auras of all Survivors. When you unhook another Survivor in the Basement, they suffer from the Broken Status Effect for 20/25/30 seconds, but you both see the Killer's Aura for 6 seconds. Additionally, you suffer no penalty from the Incapacitated Status Effect while in the Basement.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_wicked.png?813308"},{"id":117,"name":"Invocation: Weaving Spiders","code":"invocationweavingspiders","survivorCode":"sableward","survivorName":"Sable Ward","description":"An ancient ritual that requires a sacrifice. Stand in the Basement Circle of Healing and press the Active Ability button to begin the Invocation. The Invocation takes 120 seconds to complete. You suffer from the Broken Status Effect for the remainder of the Trial. When the Invocation is completed, all Survivors gain a 2/3/4% Haste Status Effect. All Invocation Perks are activated once the ritual is complete.","icon":"data:image/jpeg;base64,"},{"id":118,"name":"Friendship","code":"camaraderiefriendship","survivorCode":"sableward","survivorName":"Sable Ward","description":"Your bond with your friends is unbreakable. When within 8 meters of another Survivor, both of you benefit from a 3/4/5% Haste Status Effect. This effect lingers for 3 seconds after moving apart. Additionally, when you finish healing another Survivor, both of you see the Killer's Aura for 5 seconds.","icon":"data:image/jpeg;base64,"},{"id":119,"name":"Finesse","code":"finesse","survivorCode":"laracroft","survivorName":"Lara Croft","description":"You move with practiced grace, even under pressure. Performing a rushed vault consumes 1 Token. You start the Trial with 1/2/3 Token(s). When a vault would normally be a Medium vault, it becomes a Fast vault instead. Tokens are replenished when you perform a Slow vault or when you open a Chest.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_finesse.png?38d700"},{"id":120,"name":"Hardened","code":"hardened","survivorCode":"laracroft","survivorName":"Lara Croft","description":"You've seen worse. After you cleanse a Totem or open a Chest, you become immune to the Exposed Status Effect for 40/50/60 seconds. Additionally, your Aura cannot be read by the Killer for the same duration. Hardened deactivates once you perform a conspicuous action.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_hardened.png?38d700"},{"id":121,"name":"Specialist","code":"specialist","survivorCode":"laracroft","survivorName":"Lara Croft","description":"You know the value of preparation. Opening a Chest grants 1 Token, up to a maximum of 6/7/8 Tokens. For each Token, your Repair, Healing, and Unhooking speeds are increased by 2%. Consume 1 Token to reroll a Skill Check. Consume all Tokens to avoid losing progress when the Killer damages a Generator you are working on.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_specialist.png?38d700"},{"id":122,"name":"Exultant","code":"exultant","survivorCode":"trevorbelmont","survivorName":"Trevor Belmont","description":"You thrive in the face of darkness. Whenever you or a Survivor within 12 meters stuns the Killer, you both see the Killer's Aura for 3/4/5 seconds. If you are the one stunning the Killer, you gain the Endurance Status Effect for 6 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_Exultation.png?62d4c5"},{"id":123,"name":"Moment of Glory","code":"momentofglory","survivorCode":"trevorbelmont","survivorName":"Trevor Belmont","description":"You know how to make an entrance. When you are put into the Dying State, you can press the Active Ability button to instantly recover to the Injured State and gain the Endurance Status Effect for 6/8/10 seconds. This consumes all your remaining luck. Moment of Glory can only be used once per Trial.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_MomentOfGlory.png?6294f9"},{"id":124,"name":"Eye of Belmont","code":"eyeofbelmont","survivorCode":"trevorbelmont","survivorName":"Trevor Belmont","description":"Your bloodline has hunted evil for centuries. At the start of the Trial, the Aura of the Killer is revealed to you for 2/3/4 seconds. Whenever the Killer uses their Power within 48 meters of you, their Aura is revealed for 2 seconds. This effect has a cooldown of 30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_EyesOfBelmont.png?f94e2b"},{"id":125,"name":"Camaraderie","code":"camaraderie","survivorCode":"dustinhenderson","survivorName":"Dustin Henderson","description":"The importance of friendship has given you strength. While you are on the Hook in the Struggle Phase, if another Survivor is within 16 meters of your Hook, the Struggle Phase timer is paused for 26/30/34 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_camaraderie.png?38d700"},{"id":126,"name":"Babysitter","code":"babysitter","survivorCode":"dustinhenderson","survivorName":"Dustin Henderson","description":"You watch your friends' backs no matter what. When you unhook another Survivor, the rescued Survivor leaves no Scratch Marks or Pools of Blood for 4/6/8 seconds. Additionally, the Killer's Aura is revealed to you for 8 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_babysitter.png?38d700"},{"id":127,"name":"Second Wind","code":"secondwind","survivorCode":"dustinhenderson","survivorName":"Dustin Henderson","description":"You never give up, and your friends inspire you to keep fighting. After healing another Survivor for the equivalent of 1 Health State, Second Wind activates. The next time you are unhooked or unhook yourself, you are automatically healed 1 Health State after 20/22/24 seconds. While Second Wind is active, you suffer from the Broken Status Effect.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_secondWind.png?628298"},{"id":128,"name":"Extrasensory Perception","code":"extrasensoryperception","survivorCode":"elevenhopper","survivorName":"Eleven","description":"By slowing down and focusing, you can sense both ally and enemy. Crouch for 4 seconds to activate this perk. While active: You see the Auras of Survivors, the Killer, and a variety of objects. These are revealed in an expanding 44-meter radius. Revealed objects include Chests, Exit Gate, Generators, Hatch, Items, Pallets, Totems, and Windows. You gain the Elusive and Oblivious Status Effects. When you stop crouching, or after 11 seconds, all effects of this perk end and it enters a 60/50/40 seconds cooldown. 'What is friend?' — Eleven","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_ExtrasensoryPerception.png?2084c6"},{"id":129,"name":"Teamwork: Soft-Spoken","code":"teamworksoftspoken","survivorCode":"elevenhopper","survivorName":"Eleven","description":"You look out for your friends, using your abilities to protect them. For each other Survivor repairing a Generator with you, the range at which the Generator's repair noise is heard is reduced by 15/20/25%. While repairing with at least 1 other Survivor, you repair 5% faster. 'I make my own rules.' — Eleven","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_TeamworkSoftSpoken.png?67d34c"},{"id":130,"name":"We See You","code":"weseeyou","survivorCode":"elevenhopper","survivorName":"Eleven","description":"You've honed your powers and can turn the tables on those who try to find you. Gain 1 token when the Killer reveals your Aura. When you have 4 tokens, they are all consumed, and the Killer's aura is revealed to you and all other Survivors for 10/12.5/15%. This perk has a 10-second cooldown for gaining tokens. 'It is not me. It is you. You are the monster.' — Eleven","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_WeSeeYou.png?f6308b"},{"id":146,"name":"Apocalyptic Ingenuity","code":"apocalypticingenuity","survivorCode":"rickgrimes","survivorName":"Rick Grimes","description":"You've learned to make do with what's left behind. Sabotaging a Hook or breaking a Wall with a Toolbox is 40/50/60% faster. After completing a Generator, all Survivors within 24 meters see the Aura of the closest Exit Gate Switch for 8 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_apocalypticIngenuity.png?271ffd"},{"id":147,"name":"Come and Get Me","code":"comeandgetme","survivorCode":"rickgrimes","survivorName":"Rick Grimes","description":"You draw the fire so others can escape. When you are within 16 meters of an injured Survivor, you see the Killer's Aura. Press the Active Ability button to create a Loud Noise Notification at your location and reveal your Aura to the Killer for 3 seconds. All injured Survivors are healed for 5/7/10% of their Healing progress. Come and Get Me has a cooldown of 60 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_comeAndGetMe.png?f4490c"},{"id":148,"name":"Teamwork: Toughen Up","code":"teamworktoughenup","survivorCode":"rickgrimes","survivorName":"Rick Grimes","description":"United, you are stronger. When you heal another Survivor, both of you gain the Endurance Status Effect for 4/6/8 seconds. After the Endurance expires, both of you suffer from the Exhausted Status Effect for 40 seconds. This effect cannot be triggered again for 60 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_teamworkToughenUp.png?f0b7f2"},{"id":149,"name":"Conviction","code":"conviction","survivorCode":"michonnegrimes","survivorName":"Michonne Grimes","description":"You have an unshakeable will to live. When you are put into the Dying State, you can continue to move at 50% of normal movement speed for 2/3/4 seconds before becoming immobilized. While moving this way, you can still recover. This effect has a cooldown of 120 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_conviction.png?38d700"},{"id":150,"name":"Last Stand","code":"laststand","survivorCode":"michonnegrimes","survivorName":"Michonne Grimes","description":"When backed into a corner, you fight back. When you are the last Survivor remaining, you gain the following effects: Repair, Healing, and Unhooking speeds are increased by 25/30/35%. Your Aura is hidden from the Killer. You see the Killer's Aura when they are within 32 meters.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_lastStand.png?cb8a9f"},{"id":151,"name":"Teamwork: Throw Down","code":"teamworkthrowdown","survivorCode":"michonnegrimes","survivorName":"Michonne Grimes","description":"You watch each other's backs. When you are within 8 meters of another Survivor and the Killer breaks a Pallet, both of you see the Killer's Aura for 5/6/7 seconds. If you are the one being chased when this happens, you gain the Haste Status Effect for 3 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_teamworkThrowDown.png?69a5fd"},{"id":152,"name":"Mirrored Illusion","code":"mirroredillusion","survivorCode":"aestriyazar","survivorName":"Aestri Yazar","description":"Your bardic magic creates a distraction. When standing still for 2 seconds, press the Active Ability button to create a perfect illusion of yourself that stands in place for 10 seconds. The illusion emits a Loud Noise Notification if the Killer approaches it. Mirrored Illusion has a cooldown of 60/50/40 seconds.","icon":"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRZTJAjs1AExeed7A4RD5Pw-0xfOgRaEe1bbA&s"},{"id":153,"name":"Bardic Inspiration","code":"bardicinspiration","survivorCode":"aestriyazar","survivorName":"Aestri Yazar","description":"Your words lift the spirits of your allies. When within 8 meters of another Survivor, press the Active Ability button to grant them a random temporary benefit for 20/25/30 seconds: 5% Haste, 10% Repair Speed, or Endurance. Bardic Inspiration has a cooldown of 80 seconds and affects each Survivor only once per Trial.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_bardicInspiration.png?bae2a8"},{"id":154,"name":"Still Sight","code":"stillsight","survivorCode":"aestriyazar","survivorName":"Aestri Yazar","description":"You perceive what others miss when you remain still. When standing still for 3 seconds, you see the Auras of the Killer, Generators, and Chests within 24/28/32 meters. This effect lasts for 5 seconds after you start moving. Still Sight has a cooldown of 40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_stillSight.png?82ea5c"},{"id":155,"name":"Champion of Light","code":"championoflight","survivorCode":"alanwake","survivorName":"Alan Wake","description":"Light is your weapon against the darkness. While holding a Flashlight, your Movement speed is increased by 3/4/5%. Successfully blinding the Killer reveals their Aura to all Survivors for 6 seconds. You carry an extra Flashlight Battery.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_championOfLight.png?47998c"},{"id":156,"name":"Illumination","code":"illumination","survivorCode":"alanwake","survivorName":"Alan Wake","description":"You seek out sources of light in the darkness. The Auras of Chests and Generators within 32 meters are revealed to you. Opening a Chest reveals the Auras of all other Survivors for 5/7/10 seconds. You have a 25% chance to find an extra item when opening a Chest.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_boonIllumination.png?a90fcc"},{"id":157,"name":"Deadline","code":"deadline","survivorCode":"alanwake","survivorName":"Alan Wake","description":"Pressure makes you more focused. When you are injured, Skill Check success zones are reduced by 10/15/20%, but Great Skill Check success zones are increased by 10%. Missing a Skill Check while injured reveals the Killer's Aura to you for 3 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_deadline.png?38d700"},{"id":158,"name":"Lucky Star","code":"luckystar","survivorCode":"ellenripley","survivorName":"Ellen Ripley","description":"You know when to disappear. Hiding in a Locker suppresses your Scratch Marks and Aura for 10 seconds. When you leave the Locker, you see the Auras of all other Survivors for 5/7/10 seconds. Any healing received within 20 seconds of leaving a Locker is 50% faster.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_luckyStar.png?189218"},{"id":159,"name":"Chemical Trap","code":"chemicaltrap","survivorCode":"ellenripley","survivorName":"Ellen Ripley","description":"You jury-rig dangerous surprises. After repairing a Generator for 33%, press the Active Ability button to set a Chemical Trap on it. The first time the Killer interacts with the Generator, they are slowed by 50% for 3/4/5 seconds and suffer from the Blindness Status Effect for 30 seconds. Chemical Trap deactivates after triggering.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_chemicalTrap.png?f16588"},{"id":160,"name":"Light-Footed","code":"lightfooted","survivorCode":"ellenripley","survivorName":"Ellen Ripley","description":"You move silently when it matters most. While you are Healthy, your footsteps are silent and you leave no Scratch Marks when crouch-walking. Additionally, your Crouch Movement speed is increased by 20/25/30%.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_light-Footed.png?cdc815"},{"id":161,"name":"Scavenger","code":"scavenger","survivorCode":"gabrielsoma","survivorName":"Gabriel Soma","description":"You excel at finding resources in desolate places. When you search a Chest, there is a 25/50/75% chance it will not be consumed, allowing you to search it again. Chests you open are 30% faster and make 50% less noise.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_scavenger.png?38d700"},{"id":162,"name":"Made for This","code":"madeforthis","survivorCode":"gabrielsoma","survivorName":"Gabriel Soma","description":"Your synthetic body was built to endure. While you are healing another Survivor, both of you gain the Endurance Status Effect. After being stunned by a Pallet, you recover 10/15/20% faster for 30 seconds. Made for This causes the Exhausted Status Effect for 40 seconds after the Endurance is triggered.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_madeForThis.png?9e3242"},{"id":163,"name":"Troubleshooter","code":"troubleshooter","survivorCode":"gabrielsoma","survivorName":"Gabriel Soma","description":"You analyze threats in real-time. While in a chase, you see the Auras of Pallets and Breakable Walls within 24 meters. When the chase ends, you see the Killer's Aura for 5/7/10 seconds. Troubleshooter has a cooldown of 40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_troubleshooter.png?38d700"},{"id":164,"name":"Dramaturgy","code":"dramaturgy","survivorCode":"nicolascage","survivorName":"Nicolas Cage","description":"You live for the spotlight, even in a crisis. Press the Active Ability button to perform a dramatic gesture, granting one random effect for 20 seconds: a 5% Haste, an Item with 100% bonus charges, a 50% Action Speed bonus to your next action, or the ability to see the Killer's Aura. Dramaturgy has a 60/50/40 second cooldown and causes the Exhausted Status Effect.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_dramaturgy.png?38d700"},{"id":165,"name":"Scene Partner","code":"scenepartner","survivorCode":"nicolascage","survivorName":"Nicolas Cage","description":"You're always ready for your close-up. Whenever the Killer is within 24 meters, you can press the Active Ability button to focus on them. For the next 5/7/10 seconds, you see their Aura and hear their Terror Radius at double intensity. Scene Partner has a cooldown of 45 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_scenePartner.png?8a80ad"},{"id":166,"name":"Plot Twist","code":"plottwist","survivorCode":"nicolascage","survivorName":"Nicolas Cage","description":"You know when to take a dramatic fall. When healthy, press the Active Ability button to enter the Dying State. For the next 15 seconds, you recover at 100/125/150% speed and leave no Scratch Marks or Pools of Blood. After recovering, you gain the Endurance Status Effect for 10 seconds. Plot Twist can only be used once per Trial.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_plotTwist.png?a106be"},{"id":167,"name":"Do No Harm","code":"donoharm","survivorCode":"orelarose","survivorName":"Orela Rose","description":"Your oath to help extends beyond reason. When healing a Survivor from the Dying State, you both are shielded by the Endurance Status Effect for 6/8/10 seconds. If the Killer interrupts the heal, they are stunned for 3 seconds. Do No Harm has a cooldown of 80 seconds.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconsPerks_DoNoHarm.png?2073b4"},{"id":168,"name":"Duty of Care","code":"dutyofcare","survivorCode":"orelarose","survivorName":"Orela Rose","description":"You take responsibility for the vulnerable. Injured Survivors within 24 meters have their Auras revealed to you. When you take a hit for an injured Survivor, you both gain 10/15/20% Haste for 5 seconds and the healed Survivor's Aura is hidden for 30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconsPerks_DutyOfCare.png?a2c25e"},{"id":169,"name":"Rapid Response","code":"rapidresponse","survivorCode":"orelarose","survivorName":"Orela Rose","description":"Seconds matter when lives are on the line. When you enter a Locker, all Survivors within 24 meters see the Killer's Aura for 3/4/5 seconds. While inside a Locker, you can see the Auras of injured Survivors. Exiting a Locker gives you a 25% Haste for 3 seconds.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconsPerks_RapidResponse.png?25c13f"},{"id":170,"name":"Background Player","code":"backgroundplayer","survivorCode":"renatolyra","survivorName":"Renato Lyra","description":"When the spotlight is elsewhere, you make your move. When the Killer picks up another Survivor, you break into a sprint at 150% of your normal Running Movement speed for 6/8/10 seconds. Background Player causes the Exhausted Status Effect for 60/50/40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_backgroundPlayer.png?cdf056"},{"id":171,"name":"Blood Rush","code":"bloodrush","survivorCode":"renatolyra","survivorName":"Renato Lyra","description":"When the moment is critical, you find another wind. When you are in the Injured State and another Survivor is put into the Dying State, Blood Rush activates. Press the Active Ability button to instantly recover from the Exhausted Status Effect and gain 5/7/10% Haste for 10 seconds. Blood Rush can only be used once per Trial.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_bloodRush.png?195902"},{"id":172,"name":"Teamwork: Collective Stealth","code":"teamworkcollectivestealth","survivorCode":"renatolyra","survivorName":"Renato Lyra","description":"You hide together. When you finish healing another Survivor, both of you leave no Scratch Marks or Pools of Blood for 20/25/30 seconds. This effect ends prematurely if either of you performs a conspicuous action.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_teamworkCollectiveStealth.png?9b3acd"},{"id":173,"name":"Cut Loose","code":"cutloose","survivorCode":"thalitalyra","survivorName":"Thalita Lyra","description":"You use obstacles to your advantage. After fast-vaulting a Window, your next vault within 5 seconds is 20/25/30% faster and does not alert the Killer. Cut Loose has a cooldown of 40/35/30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_cutLoose.png?45851f"},{"id":174,"name":"Friendly Competition","code":"friendlycompetition","survivorCode":"thalitalyra","survivorName":"Thalita Lyra","description":"You bring out the best in others. When you complete a Generator with at least one other Survivor, all Survivors who worked on it gain a 5/6/7% Haste and 10% Repair speed for 40 seconds. This effect does not stack.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_friendlyCompetition.png?78ee93"},{"id":175,"name":"Teamwork: Power of Two","code":"teamworkpoweroftwo","survivorCode":"thalitalyra","survivorName":"Thalita Lyra","description":"Two are stronger than one. When you are within 8 meters of another Survivor, both of you gain a 3/4/5% Haste. When you perform a Co-operative action together, that action is 15% faster.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_teamworkPowerOfTwo.png?5cdb75"},{"id":176,"name":"Ghost Notes","code":"ghostnotes","survivorCode":"veeboonyasak","survivorName":"Vee Boonyasak","description":"While suffering from the Exhausted Status Effect, you benefit from the following effects:\\nCauses your Scratch Marks to disappear +50 % faster.\\nIncreases your Recovery rate from that Status Effect by 5/7.5/10 %.\\nGhost Notes does not cause the Exhausted Status Effect.\\n\\"Let's take it to the bridge!\\" — Vee Boonyasak","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_GhostNotes.png?92b28f"},{"id":177,"name":"One-Two-Three-Four!","code":"onetwothreefour","survivorCode":"veeboonyasak","survivorName":"Vee Boonyasak","description":"While standing and idle, press the Active Ability button to start a Performance:\\nLasts for up to 15 seconds.\\nEmpowers Survivors within 16 metres of your location.\\nTriggers continuous Skill Checks.\\nAfter successfully completing the Performance, empowered Survivors performing Healing or Repairing actions benefit from the following effect for 90 seconds:\\nIncreases the chances of triggering Skill Checks by +20 %.\\nOne-Two-Three-Four! has a cool-down of 110/100/90 seconds after cancelling or completing the Performance.\\n\\"We are loud! We are heavy! WE ARE AXEKICK!\\" — Vee Boonyasak","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_OneTwoThreeFour.png?bc3808"},{"id":178,"name":"Road Life","code":"roadlife","survivorCode":"veeboonyasak","survivorName":"Vee Boonyasak","description":"While injured and repairing a Generator, regular Skill Checks have the following effects:\\nGain +1 Token for Great Repair Skill Checks.\\nGain 0 Tokens for Good Repair Skill Checks.\\nLose -1 Token for Failed Repair Skill Checks.\\nOnce you accumulate 6/5/4 Tokens, consume all Tokens to benefit from the following effect:\\nIncreases your Healing speed by +100 % until you stop healing.\\nRoad Life deactivates after use and does not activate while suffering from the Broken Status Effect.\\nRoad Life does not interact with special Skill Checks triggered by outside effects.\\n\\"Remind me to teach you how to patch your own pedals, Krit.\\" — Vee Boonyasak","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_RoadLife.png?e0ae39"}]`),h=JSON.parse(`[{"id":0,"name":"Bitter Murmur","code":"bittermurmur","killerCode":"all","killerName":"All","description":"Unlocks potential in your Aura-reading ability:\\nEach time a Generator is completed, the Auras of all Survivors within 16 meters of that Generator are revealed to you for 5 seconds.\\nOnce the last Generator is completed, the Auras of all Survivors are revealed to you for 5/7/10 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_bitterMurmur.png"},{"id":1,"name":"Cruel Limits","code":"cruellimits","killerCode":"thedemogorgon","killerName":"The Demogorgon","description":"Your ties to the otherworldly manifest when your prey attempts to get away.\\nWhenever a Generator is completed, Cruel Limits activates:\\nBlocks every Vault location on the Map for all Survivors for the next 20/25/30 seconds.\\nThe Auras of the blocked Vault locations are highlighted to you in yellow.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c6/IconPerks_cruelLimits.png"},{"id":2,"name":"Deerstalker","code":"deerstalker","killerCode":"all","killerName":"All","description":"Unlocks potential in your Aura-reading ability:\\nThe Auras of all Survivors in the Dying State within 20/28/36 meters of your location are revealed to you.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/01/IconPerks_deerstalker.png"},{"id":3,"name":"Distressing","code":"distressing","killerCode":"all","killerName":"All","description":"Your horrifying emanation strikes at a supernaturally long distance.\\nIncreases your Terror Radius by 22/24/26%.\\nGrants 100% bonus Bloodpoints for all actions in the DeviousnessCategory.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_distressing.png"},{"id":4,"name":"Mind breaker","code":"Mindbreaker","killerCode":"all","killerName":"All","description":"Your distressing presence drains and weakens your prey.\\nWhenever a Survivor is repairing a Generator, they suffer from the Blindness and Exhausted Status Effects.\\nIf the Survivor is already Exhausted, their Status Effect's timer will be paused.\\nThe Status Effect lingers for 3/4/5 seconds after the Survivor stops repairing.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_mindbreaker.png?ff1e9e"},{"id":5,"name":"Hex: No One Escapes Death","code":"hexnooneescapesdeath","killerCode":"all","killerName":"All","description":"A Hex rooting its power on hope.\\nYou are animated by the power of your Hex Totem when the Survivors are on the verge of escaping.\\nOnce the Exit Gates are powered, if there is still a Dull Totem remaining on the Map, Hex: No One Escapes Death activates and lights it:\\nIncreases your Movement speed by 2/3/4 %.\\nSurvivors suffer from a permanent Exposed Status Effect.\\nHex: No One Escapes Death remains inactive if no Dull Totems are available.\\nOnce the Status Effect is revealed to Survivors, Hex: No One Escapes Death reveals the Aura of its Hex Totem to all Survivors within 4 metres and gradually expands that range to 24 metres over the course of 30 seconds.\\nThe Hex effects persist until its Hex Totem is cleansed.\\n\\"And the beast became faster and more powerful as if The Entity's shadowy whips were lashing at its back.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconPerks_hexNoOneEscapesDeath.png"},{"id":6,"name":"Hex: Thrill of the Hunt","code":"hexthrillofthehunt","killerCode":"all","killerName":"All","description":"A Hex rooting its power on hope.\\nThe false hope of Survivors fills you with excitement and strengthens your Totems.\\nFor each Totem remaining in the environment, Hex: Thrill of the Hunt gains 1 Token.\\nSurvivors suffer from a stack-able 8/9/10% Action Speed penalty per Token to Cleansing and Blessing, up to a maximum of 40/45/50%.\\nGrants a stack-able 10% bonus Bloodpoints for actions in the Hunter Category per Token, up to a maximum of 50%.\\nThe Hex effects persist as long as the related Hex Totem is standing.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/02/IconPerks_hexThrillOfTheHunt.png"},{"id":7,"name":"Insidious","code":"insidious","killerCode":"all","killerName":"All","description":"Unlocks your stealth ability:\\nGrants the Undetectable Status Effect after standing still for 4/3/2 seconds. The Status Effect persists until you move or perform an action.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/40/IconPerks_insidious.png"},{"id":8,"name":"Iron Grasp","code":"irongrasp","killerCode":"all","killerName":"All","description":"Your powerful grasp on Survivors causes escapes to be nearly impossible.\\nWhile carrying a Survivor you benefit from the following effects:\\nDecreases Wiggle effects, which cause you to strafe sideways, by 75%.\\nIncreases Wiggle duration by 4/8/12%.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_ironGrasp.png"},{"id":9,"name":"Jolt","code":"jolt","killerCode":"all","killerName":"All","description":"Your eerie presence charges the air and interferes with technology.\\nWhen you put a Survivor into the Dying State with your Basic Attack, all Generators within 32 meters of you instantly explode and start regressing.\\nApplies an immediate 6/7/8% Progression penalty.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_surge.png"},{"id":10,"name":"Scourge Hook: Monstrous Shrine","code":"scourgehookmonstrousshrine","killerCode":"all","killerName":"All","description":"Your fervent care of the Hooks found in the Basement has aroused The Entity's interest.\\nAt the start of the Trial, 4 random Hooks, as well as the Basement Hooks, are changed into Scourge Hooks:\\nThe Auras of Scourge Hooks are revealed to you in white.\\nEach time a Survivor is hooked on a Scourge Hook, the following effect applies whenever you are farther than 24 metres from the hooked Survivor:\\nAccelerates the Sacrifice Process by 10/15/20 %.\\n\\"Then you will know that there is no escape. When hanging in the depths, you face the dark one.\\"","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_scourgeHookMonstrousShrine.png?91c64c"},{"id":11,"name":"Sloppy Butcher","code":"sloppybutcher","killerCode":"all","killerName":"All","description":"You know where to hit to make them bleed.\\nWounds inflicted by Basic Attacks cause Survivors to suffer from the Hemorrhage and Mangled Status Effect:\\nIncreases the Bleeding frequency by 50/75/100%.\\nIncreases the rate at which incomplete Healing loses progression by 15/20/25%.\\nBoth Status Effects are removed once the Survivor is fully healed.\\n\\"It is in its sadistic nature. There is no swift kill as it delights in the obscene spectacle of our agonising suffering.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_sloppyButcher.png"},{"id":12,"name":"Spies from the Shadows","code":"spiesfromtheshadows","killerCode":"all","killerName":"All","description":"The Crows found in the Trial Grounds can communicate with you directly.\\nCrows startled by Survivors within 20/28/36 meters alert you with a Loud Noise Notification.\\nSpies from the Shadows has a cool-down of 5 seconds between alerts.\\n\\"In the shadows they torment, scarring our minds with each scream.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b1/IconPerks_spiesFromTheShadows.png"},{"id":13,"name":"Unrelenting","code":"unrelenting","killerCode":"all","killerName":"All","description":"You recuperate faster from missed attacks made with your main weapon.\\nReduces the Cool-down of missed Basic Attacks by 20/25/30%.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/57/IconPerks_unrelenting.png"},{"id":14,"name":"Whispers","code":"whispers","killerCode":"all","killerName":"All","description":"You have a rudimentary understanding of The Entity's voice.\\nYou hear the sporadic whispers of the Entity whenever at least one Survivor is within 48/40/32 meters of your location.\\n\\"It is unclear as to the motivations of The Fog, but it is undeniable that it often takes the beast's side.\\" — Unknown, Notebook","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_whispers.png"},{"id":15,"name":"Unnerving Presence","code":"unnervingpresence","killerCode":"thetrapper","killerName":"The Trapper","description":"Your presence alone instils great fear.\\nSurvivors repairing or healing within your Terror Radius suffer from the following effects:\\nIncreases the Trigger odds of Skill Check by 10 %.\\nDecreases the Success zone of Skill Checks by 40/50/60%.\\n\\"Its presence befalls us.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/IconPerks_unnervingPresence.png"},{"id":16,"name":"Brutal Strength","code":"brutalstrength","killerCode":"thetrapper","killerName":"The Trapper","description":"Your great strength allows you to shred through your prey's defences.\\nIncreases the Action speed of breaking Pallets and Breakable Walls, and damaging Generators by 10/15/20%.\\n\\"It is more than muscles. A dark power motivates the beast.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3d/IconPerks_brutalStrength.png"},{"id":17,"name":"Agitation","code":"agitation","killerCode":"thetrapper","killerName":"The Trapper","description":"You get excited in anticipation of hooking your prey.\\nWhile carrying a Survivor you benefit from the following effects:\\nIncreases your Carrying Movement speed by 6/12/18%.\\nIncreases your Terror Radius by 12 meters.\\n\\"At some point, the excitement of hooking one of us becomes more important than the desire to kill us.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ac/IconPerks_agitation.png"},{"id":18,"name":"Predator","code":"predator","killerCode":"thewraith","killerName":"The Wraith","description":"Your acute tracking ability allows you to hone in on disturbances left by running Survivors.\\nThe Scratch Marks left by Survivors spawn slightly/moderately/considerably closer together.\\n\\"Never stop moving and hope you're always two steps ahead of the beast.\\" — Unknown, Notebook","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/73/IconPerks_predator.png"},{"id":19,"name":"Bloodhound","code":"bloodhound","killerCode":"thewraith","killerName":"The Wraith","description":"Like a hunting scent hound, you smell traces of blood at a great distance.\\nPools of Blood are shown in bright red and can be tracked for 2/3/4 seconds longer than normal.\\n\\"Pebbles shimmering in the moonlight; my life drips down in a trail so easy to follow.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconPerks_bloodhound.png"},{"id":20,"name":"Shadowborn","code":"shadowborn","killerCode":"thewraith","killerName":"The Wraith","description":"You have a keep vision in the darkness of the night.\\nIncreases your Field of View by 9/12/15°.\\nField of View gains do not stack.\\n\\"Shining in the darkest dark, his eyes pierce the night and sting your soul.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ac/IconPerks_shadowborn.png"},{"id":21,"name":"Enduring","code":"enduring","killerCode":"thehillbilly","killerName":"The Hillbilly","description":"You are resilient to pain.\\nReduces Pallet Stun duration by 40/45/50 %.\\nEnduring has no effect while carrying a Survivor.\\n\\"He stops at nothing.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_enduring.png"},{"id":22,"name":"Lightborn","code":"lightborn","killerCode":"thehillbilly","killerName":"The Hillbilly","description":"Unlike other beasts of The Fog, you have adapted to light.\\nThe Auras of Survivors attempting to blind you with a Flashlight are revealed to you for 6/8/10 seconds.\\nLightborn grants immunity from being blinded by Flashlights, Firecrackers, Flashbangs, or Blast Mines.\\n\\"These monsters... they adapt! They emerge with strange new abilities.\\" — Vigo, Vigo's Journal","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/48/IconPerks_lightborn.png"},{"id":23,"name":"Tinkerer","code":"tinkerer","killerCode":"thehillbilly","killerName":"The Hillbilly","description":"Whenever a Generator is repaired to 70%, you benefit from the following effects:\\nTriggers a Loud Noise Notification for that Generator, revealing its location.\\nGrants the Undetectable Status Effect for the next 12/14/16 seconds.\\nTinkerer can only trigger once per Generator per Trial.\\n\\"The Hillbilly makes impressive tools out of scraps. Tools aimed at maiming us in creative ways.\\" — Notebook","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d9/IconPerks_tinkerer.png"},{"id":24,"name":"Stridor","code":"stridor","killerCode":"thenurse","killerName":"The Nurse","description":"You are acutely sensitive to the breathing of your prey.\\nIncreases the volume of Survivors' Grunts of Pain by 25/50/50%.\\nIncreases the volume of Survivors' regular breathing by 0/0/25%.\\n\\"If you do not stop and catch your breath... she will.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/32/IconPerks_stridor.png"},{"id":25,"name":"Thanatophobia","code":"thanatophobia","killerCode":"thenurse","killerName":"The Nurse","description":"Their courage fades in the face of their undeniable mortality.\\nFor each injured, dying or hooked Survivor, all Survivors receive an Action Speed penalty of 1/1.5/2 % to Repairing, Sabotaging, and Cleansing, stack-able up to a maximum of 4/6/8 %.\\nIf all four Survivors are either injured, dying or hooked, the Penalty is further increased by +12 %.\\n\\"She plays with us and revels in our pain.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_thanatophobia.png"},{"id":26,"name":"A Nurse's Calling","code":"anursescalling","killerCode":"thenurse","killerName":"The Nurse","description":"Unlocks potential in your Aura-reading ability.\\nThe Auras of Survivors, who are healing or being healed, are revealed to you when they are within a range of 20/24/28 meters.\\n\\"Still attached to the fragments of her past life, she is drawn to those in need of help.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fe/IconPerks_aNursesCalling.png"},{"id":27,"name":"Save The Best for Last","code":"savethebestforlast","killerCode":"theshape","killerName":"The Shape","description":"You become obsessed with one Survivor.\\nEach time you hit a Survivor other than your Obsession with a Basic Attack, Save the Best for Last gains 1 Token, up to a maximum of 8 Tokens:\\nGain a stack-able 5% Cool-down reduction on successful attacks per Token, up to a maximum of 40%.\\nEach time you hit your Obsession with a Basic Attack, Save the Best for Last loses 4/3/2 Tokens.\\nWhen the Obsession is sacrificed or killed, you can neither gain nor lose any more Tokens.\\nYou can only be obsessed with one Survivor at a time.\\n\\"Death has come to your little town, Sheriff.\\" — Dr Sam Loomis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconPerks_saveTheBestForLast.png"},{"id":28,"name":"Play with Your Food","code":"playwithyourfood","killerCode":"theshape","killerName":"The Shape","description":"You become obsessed with one Survivor.\\nEach time you chase your Obsession and let them escape, Play with Your Food recieves 1 Token, up to a maximum of 3 Tokens:\\nEach Token applies a stack-able 3/4/5% Haste Status Effect, up to a maximum of 9/12/15%.\\nPerforming Basic Attacks, or Special Attacks that can damage Survivors, consumes 1 Token.\\nPlay with Your Food has a cool-down of 10 seconds on Token-accumulation.\\nYou can only be obsessed with one Survivor at a time.\\n\\"You've fooled them, haven't you Michael? But not me.\\" — Dr Sam Loomis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/18/IconPerks_playWithYourFood.png"},{"id":29,"name":"Dying Light","code":"dyinglight","killerCode":"theshape","killerName":"The Shape","description":"Each time you hook a Survivor other than your Obsession, you gain +1 Token:\\nFor as long as the Obsession is alive, all other Survivors suffer from a stack-able 2/2.5/3 % per Token Action Speed penalty to Repairing, Healing, and Sabotaging, up to a maximum of 22/27.5/33 % or 11 Tokens.\\nThe Obsession is unaffected by this penalty and instead granted a permanent +33 % Action Speed bonus to Unhooking and Healing other Survivors.\\nYou can only be obsessed with one Survivor at a time.\\n\\"This isn't a man...\\" — Dr Sam Loomis","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/48/IconPerks_dyingLight.png"},{"id":30,"name":"Hex: The Third Seal","code":"hexthethirdseal","killerCode":"thehag","killerName":"The Hag","description":"A Hex that hinders the Survivors' Aura-reading abilities.\\nThe last 2/3/4 Survivors hit with either your Basic Attack or Special Attack suffer from the Blindness Status Effect.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"She touched your skin, you bear the witch's mark!\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/36/IconPerks_hexTheThirdSeal.png"},{"id":31,"name":"Hex: Ruin","code":"hexruin","killerCode":"thehag","killerName":"The Hag","description":"A Hex that affects the Generator Repair progress of all Survivors.\\nWhenever a Generator is not being repaired by a Survivor, it will immediately and automatically regress its Repair progress at 50/75/100 % of the normal Regression speed.\\nOnce any Survivor is killed by any means, Hex: Ruin deactivates and reverts its Hex Totem into a Dull Totem.\\nThe Hex effects persist until its Hex Totem is cleansed.\\n\\"A curse is upon you. It will cause your ruin.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_hexRuin.png"},{"id":32,"name":"Hex: Devour Hope","code":"hexdevourhope","killerCode":"thehag","killerName":"The Hag","description":"A Hex rooting its power on hope.\\nThe false hope of Survivors ignites your hunger.\\nEach time a Survivor is rescued from a Hook when you are at least 24 meters away, Hex: Devour Hope receives 1 Token:\\n2 Tokens: 10 seconds after hooking a Survivor, gain a 3/4/5 % Haste Status Effect for the next 10 seconds.\\n3 Tokens: Survivors suffer permanently from the Exposed Status Effect.\\n5 Tokens: You are granted the ability to kill all Survivors by your own hand.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"If you do nothing, you have their blood on your hands. If you save them, her hunger grows.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c9/IconPerks_hexDevourHope.png"},{"id":33,"name":"Overwhelming Presence","code":"overwhelmingpresence","killerCode":"thedoctor","killerName":"The Doctor","description":"Your presence alone instils great fear.\\nSurvivors within your Terror Radius suffer from inefficiency:\\nWhen using an Item, its Depletion rate is increased by 80/90/100%.\\n\\"Shit!! I dropped the gauze!\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconPerks_overwhelmingPresence.png"},{"id":34,"name":"Monitor & Abuse","code":"monitorandabuse","killerCode":"thedoctor","killerName":"The Doctor","description":"Meticulous in your approach, terrifying in your application.\\nYour base Terror Radius is increased by 8 meters.\\nWhenever you are outside of a Chase, your Terror Radius is reduced by 16 meters while your Field of View is increased by 3/5/10°.\\nField of View gains do not stack.\\n\\"Its time for your treatment!\\" — Herman Carter, The Doctor","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/60/IconPerks_monitorAndAbuse.png"},{"id":35,"name":"Overcharge","code":"overcharge","killerCode":"thedoctor","killerName":"The Doctor","description":"You are fuelled by your hate for progress.\\nPerforming the Damage Generator Action on a Generator applies Overcharge:\\nThe next Survivor interacting with that Generator is faced with a difficult Skill Check.\\nFailing the Skill Check results in an immediate Progression loss of 3/4/5 %.\\nSucceeding the Skill Check grants no bonus Progression, but prevents the Generator from exploding.\\nAfter Overcharge is applied to a Generator, the following effect applies:\\nIncreases the Regression speed from 75 % to 200 % over the next 30 seconds.\\n\\"Its a trap, But a trap one must step in...\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_overcharge.png"},{"id":36,"name":"Beast of Prey","code":"beastofprey","killerCode":"thehuntress","killerName":"The Huntress","description":"Your lust for a kill is so intense that your connection with The Entity is momentarily lost, making you totally unpredictable.\\nUpon gaining the Bloodlust Status Effect, Beast of Prey activates:\\nGrants the Undetectable Status Effect for as long as Bloodlust is active.\\nBeast of Prey grants 30/40/50% bonus Bloodpoints for actions in the Hunter Category.\\nThe bonus Bloodpoints are only awarded during the Trial.\\n\\"Where did she go?\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/77/IconPerks_beastOfPrey.png"},{"id":37,"name":"Territorial Imperative","code":"territorialimperative","killerCode":"thehuntress","killerName":"The Huntress","description":"Unlocks potential in your Aura-reading ability.\\nThe Aura of a Survivor entering the Basement when you are at least 32 meters away is revealed to you for 3 seconds.\\nTerritorial Imperative has a cool-down of 30/25/20 seconds.\\n\\"We're not safe anywhere...\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2a/IconPerks_territorialImperative.png"},{"id":38,"name":"Hex: Huntress Lullaby","code":"hexhuntresslullaby","killerCode":"thehuntress","killerName":"The Huntress","description":"A Hex rooting its power in despair.\\nYour hunt is an irresistible song of dread which muddles your prey's attention.\\nSurvivors receive a 2/4/6% Regression penalty on Failed Skill Checks for Repair and Healing actions.\\nHex: Huntress Lullaby grows in power each time you Hook a Survivor, gaining 1 Token, and affecting Repair and Healing Skill Checks:\\n1 Token: shortens the time between the Warning sound and the Skill check by 14%.\\n2 Tokens: shortens the time between the Warning sound and the Skill check by 28%.\\n3 Tokens: shortens the time between the Warning sound and the Skill check by 42%.\\n4 Tokens: shortens the time between the Warning sound and the Skill check by 56%.\\n5 Tokens: disables the Warning sound.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"That song, it drives me crazy!\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/11/IconPerks_hexHuntressLullaby.png"},{"id":39,"name":"Knock Out","code":"knockout","killerCode":"thecannibal","killerName":"The Cannibal","description":"The trauma caused by your brutal attacks makes crying for help painfully difficult.\\nPutting a Survivor into the Dying State with your Basic Attack blocks their Aura from being revealed to any Survivor, who is farther than 32/24/16 metres away from them.\\nThe dying Survivor suffers from the Blindness Status Effect and has their Field of View reduced for the next 15 seconds.\\n\\"Oh, that gun's no good. The old way... with a sledge! You see, that way's better. They die better that way.\\" — Nubbins Sawyer","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_knockOut.png"},{"id":40,"name":"Barbecue & Chilli","code":"barbecueandchilli","killerCode":"thecannibal","killerName":"The Cannibal","description":"A deep bond with The Entity unlocks potential in one's Aura-reading ability.\\nAfter hooking a Survivor, all Survivors who are at least 60/50/40 metres away from that Hook have their Aura revealed to you for 5 seconds.\\n\\"I just can't take no pleasure in killing. There's just some things you gotta do. Don't mean you have to like it.\\" — Drayton Sawyer","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_barbecueAndChilli.png?b6f08b"},{"id":41,"name":"Franklin's Demise","code":"franklinsdemise","killerCode":"thecannibal","killerName":"The Cannibal","description":"Your vicious Basic Attacks make Survivors drop their Items on impact.\\nIf not recovered within 150/120/90 seconds, the lost Items will have their Charges depleted by The Entity.\\nThe Auras of lost Items are revealed to you within 32 meters and slowly fade from white to red as the timer elapses.\\n\\"Sally, I hear something. Stop! Stop!\\" — Franklin Hardesty","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b2/IconPerks_franklinsDemise.png"},{"id":42,"name":"Fire Up","code":"fireup","killerCode":"thenightmare","killerName":"The Nightmare","description":"The increased pressure of losing your preys fills you with anger and gives you unsuspected motivation.\\nEach time a Generator is completed, Fire Up grows in power and gains 1 Token, up to a maximum of 5 Tokens.\\nEach Token applies a stack-able buff of 3/3.5/4 % per Token, up to a maximum of 15/17.5/20 %, to the following Actions: Picking up and dropping Survivors, breaking Pallets and Breakable Walls, damaging Generators, and vaulting Windows.\\n\\"Now why don't you just fucking die?\\" — Freddy Krueger","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5c/IconPerks_fireUp.png"},{"id":43,"name":"Remember Me","code":"rememberme","killerCode":"thenightmare","killerName":"The Nightmare","description":"You become obsessed with one Survivor.\\nEach time the Obsession loses a Health State, Remember Me gains 1 Token:\\nIncreases the Opening time of both Exit Gates by 4 seconds per Token, up to a maximum of 8/12/16 additional seconds.\\nThe Obsession remains unaffected by this penalty.\\nYou can only be obsessed with one Survivor at a time.\\n\\"You don't remember? You must. You're my number one, and you'll never wake up again.\\" — Freddy Krueger","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/62/IconPerks_rememberMe.png"},{"id":44,"name":"Blood Warden","code":"bloodwarden","killerCode":"thenightmare","killerName":"The Nightmare","description":"As soon as one Exit Gate is opened, Blood Warden activates.\\nThe Auras of Survivors standing within the Exit-Gate area are revealed to you.\\nOnce per Trial, hooking a Survivor while Blood Warden is active calls upon The Entity to block the exits for all Survivors for 40/50/60 seconds.\\n\\"This is my world. And you can't ever leave.\\" — Freddy Krueger","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_bloodWarden.png"},{"id":45,"name":"Hangman's Trick","code":"hangmanstrick","killerCode":"thepig","killerName":"The Pig","description":"Unlocks potential in your Aura-reading ability and your ingenious modifications to Hooks alert you of tampering.\\nGain a Loud Noise Notification whenever a Survivor begins sabotaging a Hook.\\nWhile carrying a Survivor, see the Aura of any Survivor within 2/4/6 meters of any Hook.\\n\\"No excuses, no equivocations... No crying.\\" — Amanda Young","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_scourgeHookHangmansTrick.png?fb70f3"},{"id":46,"name":"Surveillance","code":"surveillance","killerCode":"thepig","killerName":"The Pig","description":"Unlocks potential in your Aura-reading ability.\\nThe Auras of regressing Generators are highlighted in white.\\nIf the Regression progress is interrupted on a Generator, its Aura will be highlighted in yellow for 8/12/16 seconds.\\nSurveillance increases the audible range of Survivors' Generator-repairing noises by 8 meters.\\n\\"Are you gonna behave?\\" — Amanda Young","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_surveillance.png"},{"id":47,"name":"Make Your Choice","code":"makeyourchoice","killerCode":"thepig","killerName":"The Pig","description":"Each time a Survivor is rescued from a Hook when you are at least 32 meters away, Make Your Choice activates:\\nThe Rescuer screams and suffers from the Exposed Status Effect for the next 40/50/60 seconds.\\nMake Your Choice has a cooldown of 40/50/60 seconds.\\n\\"You'd be surprised what tools can save a life.\\" — Amanda Young","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6b/IconPerks_makeYourChoice.png"},{"id":48,"name":"Bamboozle","code":"bamboozle","killerCode":"theclown","killerName":"The Clown","description":"After vaulting a Window, Bamboozle calls upon The Entity to block that Window for the next 8/12/16 seconds.\\nBlocked Windows cannot be vaulted by Survivors.\\nIncreases your general Vaulting speed by 5/10/15%.\\nBamboozle only blocks one Window at a time and does not apply either of its effects to vaulting Pallets.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconPerks_bamboozle.png"},{"id":49,"name":"Coulrophobia","code":"coulrophobia","killerCode":"theclown","killerName":"The Clown","description":"Even those without a fear of clowns know to be terrified of you.\\nFor all Survivors within your Terror Radius, the following effects apply:\\nReduces their Healing speed by 30/40/50 %.\\nIncreases the Rotation speed of Healing Skill Checks by +50 %.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/45/IconPerks_coulrophobia.png"},{"id":50,"name":"Pop Goes the Weasel","code":"popgoestheweasel","killerCode":"theclown","killerName":"The Clown","description":"A deep bond with The Entity unlocks great strength.\\nAfter hooking a Survivor, Pop Goes the Weasel activates for the next 35/40/45 seconds:\\nPerforming the Damage Generator Action on a Generator instantly regresses it by -20 % of its current Progression, after which normal Regression applies.\\nPop Goes the Weasel deactivates after damaging a Generator or when its timer elapses.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0f/IconPerks_popGoesTheWeasel.png"},{"id":51,"name":"Spirit Fury","code":"spiritfury","killerCode":"thespirit","killerName":"The Spirit","description":"Each Pallet you break magnifies the wrath of The Entity.\\nAfter breaking 4/3/2 Pallets, the next time you are stunned by a Pallet, The Entity will instantly break it.\\nYou still suffer from the Stun penalty.\\n\\"Fury is her blood.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a6/IconPerks_spiritFury.png"},{"id":52,"name":"Hex: Haunted Ground","code":"hexhauntedground","killerCode":"thespirit","killerName":"The Spirit","description":"Two trapped Hex Totems will spawn in the Trial Grounds.\\nWhen either Hex Totem is cleansed or blessed, all Survivors suffer from the Exposed Status Effect for 40/50/60 seconds.\\nThe second Hex Totem will immediately turn into a Dull Totem.\\n\\"Her home become profane.\\"","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconPerks_hexHauntedGround.png"},{"id":53,"name":"Rancor","code":"rancor","killerCode":"thespirit","killerName":"The Spirit","description":"You become obsessed with one Survivor.\\nEach time a Generator is completed:\\nYour Aura is revealed to the Obsession for 5/4/3 seconds.\\nAll Survivors' locations are revealed to you for 3 seconds.\\nOnce all Generators are completed:\\nThe Obsession suffers from a permanent Exposed Status Effect.\\nYou are granted the ability to kill the Obsession by your own hand.\\nYou can only be obsessed with one Survivor at a time.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_rancor.png"},{"id":54,"name":"Discordance","code":"discordance","killerCode":"thelegion","killerName":"The Legion","description":"Any Generator within a range of 64/96/128 metres that is being repaired by 2 or more Survivors is marked by a yellow Aura.\\nWhen the Generator is first highlighted, Discordance triggers a Loud Noise Notification on the Generator.\\nAfter the Generator is no longer within range or is being repaired by just 1 Survivor, the highlighted Aura will linger for another 4 seconds.\\n\\"Smartasses get killed. We always see to that.\\" — The Legion","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/82/IconPerks_discordance.png"},{"id":55,"name":"Mad Grit","code":"madgrit","killerCode":"thelegion","killerName":"The Legion","description":"While carrying a Survivor, you suffer no cool-down on missed attacks.\\nSuccessfully hitting a Survivor will pause the carried Survivor's Wiggling Progression for 2/3/4 seconds.\\n\\"There's no getting out of this now. We're too good at it.\\" — The Legion","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/da/IconPerks_madGrit.png"},{"id":56,"name":"Iron Maiden","code":"ironmaiden","killerCode":"thelegion","killerName":"The Legion","description":"You open Lockers 30/40/50% faster.\\nSurvivors who exit Lockers will scream and suffer from the Exposed Status Effect for 30 seconds and their location is revealed to you for 4 seconds.\\n\\"This is no place for cowards.\\" — The Legion","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b0/IconPerks_ironMaiden.png"},{"id":57,"name":"Corrupt Intervention","code":"corruptintervention","killerCode":"theplague","killerName":"The Plague","description":"Your prayers invoke a dark power that meddles with the Survivors' chances of survival.\\nAt the start of the Trial, the 3 Generators located farthest from you are blocked by The Entity for 80/100/120 seconds.\\nCorrupt Intervention deactivates prematurely once the first Survivor is put into the Dying State.\\n\\"It shall be known across the land that the Gods curse the unfaithful.\\" — (The Tablet of Adiris, 3.7)","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/10/IconPerks_corruptIntervention.png"},{"id":58,"name":"Infectious Fright","code":"infectiousfright","killerCode":"theplague","killerName":"The Plague","description":"The cries of the unfaithful make your heart leap.\\nWhenever a Survivor is put into the Dying State by any means, all other Survivors within your Terror Radius will scream and reveal their current location to you for 4/5/6 seconds.\\n\\"Horror overcomes the heart of infidels who cry at the feet of the fallen.\\" — (Hymn of Praise, 11.4)","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6d/IconPerks_infectiousFright.png"},{"id":59,"name":"Dark Devotion","code":"darkdevotion","killerCode":"theplague","killerName":"The Plague","description":"The display of your Powers creates a whirlwind of panic that spreads throughout the land.\\nYou become obsessed with one Survivor.\\nWhenever the Obsession loses a Health State by any means and thus enters the Injured State, Dark Devotion activates:\\nYour Terror Radius transfers to the Obsession for 20/25/30 seconds, and its radius is set to 32 metres.\\nGrants the Undetectable Status Effect for the same duration.\\nThe Obsession with your transferred Terror Radius is also considered to be 'inside the Terror Radius' for other purposes.\\nYou can only be obsessed with one Survivor at a time.\\n\\"And terror shall take hold of a defiant non-believer, who shall falsely announce my arrival.\\" — (The Tablet of Adiris, 48.9)","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconPerks_darkDevotion.png"},{"id":60,"name":"I'm All Ears","code":"imallears","killerCode":"theghostface","killerName":"The Ghost Face","description":"Unlocks potential in your Aura-reading ability, sharpening your keen senses in the dark Realm of The Entity.\\nAny Survivor performing a rushed action within 48 meters of your location has their Aura revealed to you for 6 seconds.\\nI'm All Ears can only be triggered once every 60/50/40 seconds.\\n\\"There is no need to worry. I've been preparing my whole life for this.\\" — The Ghost Face","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e3/IconPerks_imAllEars.png"},{"id":61,"name":"Thrilling Tremors","code":"thrillingtremors","killerCode":"theghostface","killerName":"The Ghost Face","description":"Your dark designs and shrewd composure rouse The Entity.\\nAfter picking up a Survivor, all Generators not currently being repaired by Survivors are blocked by The Entity for the next 16 seconds.\\nThe Auras of blocked Generators are highlighted to you in white.\\nThrilling Tremors has a cool-down of 100/80/60 seconds.\\n\\"The night assists me and it's endless here.\\" — The Ghost Face","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b8/IconPerks_thrillingTremors.png"},{"id":62,"name":"Furtive Chase","code":"furtivechase","killerCode":"theghostface","killerName":"The Ghost Face","description":"You become obsessed with one Survivor.\\nYou lurk in the shadows, eliminating your victims one by one.\\nEach time you hook your Obsession, you gain 1 Token, up to a maximum of 2/3/4 Tokens:\\nWhile in a Chase, your Terror Radius is reduced by 4 meters per accumulated Token.\\nWhen a Survivor rescues the Obsession from the Hook, that Survivor will become the new Obsession.\\nYou can only be obsessed with one Survivor at a time.\\n\\"You have no idea what I have planned for you. It'll be in the news for weeks. I'll make sure of that.\\" — The Ghost Face","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_furtiveChase.png"},{"id":63,"name":"Zanshin Tactics","code":"zanshintactics","killerCode":"theoni","killerName":"The Oni","description":"Unlocks potential in your Aura-reading ability.\\nYou are mentally alert and aware of key points on the battlefield.\\nThe Auras of Breakable Walls, Pallets, and Windows are revealed to you within 24/28/32 meters.\\n\\"Within your enemy's strength is weakness.\\" — Renjiro's Doctrine 12:5","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d3/IconPerks_zanshinTactics.png"},{"id":64,"name":"Blood Echo","code":"bloodecho","killerCode":"theoni","killerName":"The Oni","description":"The agony of one is inflicted onto others.\\nWhenever you hook a Survivor, all other injured Survivors suffer from the Exhausted and Haemorrhage Status Effects for 20/25/30 seconds.\\nBlood Echo can only be triggered once every 80/70/60 seconds.\\n\\"Attack an enemy with precision and their allies will feel it.\\" — Renjiro's Doctrine 6:3","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_bloodEcho.png"},{"id":65,"name":"Nemesis","code":"nemesis","killerCode":"theoni","killerName":"The Oni","description":"You seek retribution on those who have wronged you.\\nAny Survivor who blinds or stuns you becomes the Obsession.\\nAnytime your Obsession switches to another Survivor by any means, that Survivor then suffers from the Oblivious Status Effect for 40/50/60 seconds and their Aura is revealed to you for 4 seconds.\\nYou can only be obsessed with one Survivor at a time.\\n\\"Only a fool would spit in a demon's face and declare victory.\\" — Renjiro's Doctrine 4:9","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/33/IconPerks_nemesis.png"},{"id":66,"name":"Gearhead","code":"gearhead","killerCode":"thedeathslinger","killerName":"The Deathslinger","description":"After a Survivor loses a Health State, Gearhead activates:\\nWhile Gearhead is active, a Survivor succeeding a Great Skill Check while repairing reveals their Aura to you for 6/8/10 seconds, after which Gearhead deactivates.\\n\\"Sometimes a man's best work is what puts him in the grave.\\" — The Prison Warden","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fd/IconPerks_gearhead.png"},{"id":67,"name":"Dead Man's Switch","code":"deadmansswitch","killerCode":"thedeathslinger","killerName":"The Deathslinger","description":"After hooking a Survivor, Dead Man's Switch activates:\\nBlocks the first Generator any Survivor stops repairing for 40/45/50 seconds.\\nThe Blocked Generator is highlighted to you in white.\\nDead Man's Switch cannot activate if its effect is still active from a previous activation.\\n\\"I've seen the look on a man's face when he realises he's going to die.\\" — Caleb Quinn","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_deadMansSwitch.png"},{"id":68,"name":"Hex: Retribution","code":"hexretribution","killerCode":"thedeathslinger","killerName":"The Deathslinger","description":"A Hex that lashes out upon its destruction.\\nThose who cross you will be punished.\\nSurvivors cleansing or blessing any Totem suffer from the Oblivious Status Effect for 35/40/45 seconds.\\nAfter cleansing or blessing a Hex Totem, the Auras of all Survivors are revealed to you for 15 seconds.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"Bloody fool, you pulled the trigger on yourself.\\" — Caleb Quinn","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ab/IconPerks_hexRetribution.png"},{"id":69,"name":"Forced Penance","code":"forcedpenance","killerCode":"theexecutioner","killerName":"The Executioner","description":"Those who stand in the way of duty will suffer harsh judgement.\\nSurvivors who take a Protection Hit suffer from the Broken Status Effect for the next 60/70/80 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_forcedPenance.png"},{"id":70,"name":"Trail of Torment","code":"trailoftorment","killerCode":"theexecutioner","killerName":"The Executioner","description":"You guide your victims along a path of pain and punishment.\\nAfter kicking a Generator, you are granted the Undetectable Status Effect until that Generator stops regressing or you damage a Survivor by any means.\\nThe Aura of that Generator is revealed to all Survivors in yellow.\\nTrail of Torment has a cool-down of 80/70/60 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_trailOfTorment.png"},{"id":71,"name":"Deathbound","code":"deathbound","killerCode":"theexecutioner","killerName":"The Executioner","description":"Those whose lives are intertwined in darkness are destined to suffer together.\\nWhenever a Survivor finishes healing another Survivor for the equivalent of 1 Health State, Deathbound activates:\\nCauses the Healer to scream and reveal their location.\\nCauses the Healer to suffer from the Oblivious Status Effect whenever they are farther than 16/12/8 metres from the other Survivor.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconPerks_deathbound.png"},{"id":72,"name":"Dragon's Grip","code":"dragonsgrip","killerCode":"theblight","killerName":"The Blight","description":"Performing the Damage Generator action on a Generator activates Dragon's Grip for the next 30 seconds:\\nThe first Survivor interacting with the damaged Generator will scream, revealing their location for 4 seconds, and suffer from the Exposed Status Effect for 60 seconds.\\nDragon's Grip has a cool-down of 60/50/40 seconds.\\n\\"Such potential in this compound... even the slightest trace causes unnatural effects.\\" — Journal of Talbot Grimes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/IconPerks_dragonsGrip.png"},{"id":73,"name":"Hex: Blood Favour","code":"hexbloodfavour","killerCode":"theblight","killerName":"The Blight","description":"A Hex that gains the favour of The Entity when blood is spilt.\\nWhenever a Survivor loses a Health State by any means and thus enters the Injured State, Hex: Blood Favour calls upon The Entity to block all Pallets within 24/28/32 meters of that Survivor's location from being pulled down for the next 15 seconds.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"It would be no leap of the imagination to suggest that the Trials are a biological response of sorts.\\" — Journal of Talbot Grimes","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_hexBloodFavour.png?2a0118"},{"id":74,"name":"Hex: Undying","code":"hexundying","killerCode":"theblight","killerName":"The Blight","description":"A Hex which maintains the vile powers that flow throughout the Trial.\\nThe Auras of Survivors within 2/3/4 meters of any Dull Totem are revealed to you.\\nWhen another Perk's Hex Totem is cleansed or blessed, its Hex is transferred to the Hex: Undying Totem, including any accumulated Tokens, disabling Hex: Undying instead.\\nThe Hex effects persist as long as the related Hex Totem is standing.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fe/IconPerks_hexUndying.png"},{"id":75,"name":"Hoarder","code":"hoarder","killerCode":"thetwins","killerName":"The Twins","description":"You protect what little you have and are perceptive to those rummaging through your stockpiles.\\nHoarder triggers a Loud Noise Notification for 4 seconds, whenever a Survivor performs any of the following actions within 32/48/64 meters of your location:\\nUnlocks a Chest.\\nPicks up any Item, including Limited Items.\\nHoarder spawns 2 additional chests in the Trial.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/23/IconPerks_hoarder.png"},{"id":76,"name":"Oppression","code":"oppression","killerCode":"thetwins","killerName":"The Twins","description":"Life has been difficult for you, so you will make it difficult for others.\\nWhen damaging a Generator, up to 3 other random Generators also begin regressing.\\nTrigger a difficult Skill Check if a selected Generator is being repaired.\\nOppression has a cool-down of 120/100/80 seconds.\\n\\"Damn them as they would damn us.\\" — Charlotte Deshayes","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a1/IconPerks_oppression.png"},{"id":77,"name":"Coup de Grâce","code":"coupdegrace","killerCode":"thetwins","killerName":"The Twins","description":"As the end nears, you go in for the kill.\\nWhenever a Generator is completed, Coup de Grâce gains +2 Tokens, up to a maximum of 10 Tokens per Trial:\\nIncreases the range of your next Lunge Attack by 70/75/80 %, while consuming -1 Token.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bd/IconPerks_coupDeGr%C3%A2ce.png"},{"id":78,"name":"Starstruck","code":"starstruck","killerCode":"thetrickster","killerName":"The Trickster","description":"Your unmatched showmanship dazzles all.\\nWhen carrying a Survivor, Starstruck activates:\\nSurvivors suffer from the Exposed Status Effect while in your Terror Radius.\\nThe Status Effect lingers for 26/28/30 seconds after leaving your Terror Radius.\\nAfter hooking or dropping the carried Survivor, Starstruck deactivates:\\nThe Status Effect persists for 26/28/30 seconds for any Survivor inside your Terror Radius at that moment.\\nStarstruck has a cool-down of 60 seconds once the Survivor is no longer being carried.\\n\\"Enjoy this moment, few get so close.\\" — Ji-Woon Hak","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6e/IconPerks_starstruck.png"},{"id":79,"name":"Hex: Crowd Control","code":"hexcrowdcontrol","killerCode":"thetrickster","killerName":"The Trickster","description":"A Hex that ensures those lesser than you are properly herded.\\nSurvivors who perform a rushed vault through a Window prompt The Entity to block it for the next 14/17/20 seconds.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"You have no control. People like you never did.\\" — Ji-Woon Hak","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f1/IconPerks_hexCrowdControl.png"},{"id":80,"name":"No Way Out","code":"nowayout","killerCode":"thetrickster","killerName":"The Trickster","description":"You are not going to let just anyone into the VIP room.\\nFor each Survivor you hook for the first time, No Way Out gains 1 Token.\\nOnce the Exit Gates have been powered, No Way Out activates:\\nWhen a Survivor interacts with an Exit Gate Switch, you receive a Loud Noise Notification and The Entity blocks both Exit Gate Switches for 12 seconds and an additional 6/9/12 seconds per Token in your possession, up to a combined maximum of 36/48/60 seconds.\\n\\"That sound when you bleed... let me hear it again.\\" — Ji-Woon Hak","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_noWayOut.png"},{"id":81,"name":"Lethal Pursuer","code":"lethalpursuer","killerCode":"thenemesis","killerName":"The Nemesis","description":"You have been designed to track down and eliminate targets.\\nAt the start of the Trial, the Auras of all Survivors are revealed to you for 7/8/9 seconds.\\nExtends the duration of a Survivor's Aura being revealed to you by +2 seconds.\\nLethal Pursuer benefits from its own effect.\\n\\"...it knows what it wants and won't stop till it gets it.\\" — Carlos Oliveira","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/61/IconPerks_lethalPursuer.png"},{"id":82,"name":"Hysteria","code":"hysteria","killerCode":"thenemesis","killerName":"The Nemesis","description":"You know how to brutalise one member of a team to cause a panic.\\nWhenever you put a healthy Survivor into the Injured State, all injured Survivors suffer from the Oblivious Status Effect for 20/25/30 seconds.\\nHysteria has a cool-down of 30 seconds.\\n\\"Sorry I got a little jumpy there. Didn't know quite what to expect.\\" — Robert Kendo","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3a/IconPerks_hysteria.png"},{"id":83,"name":"Eruption","code":"eruption","killerCode":"thenemesis","killerName":"The Nemesis","description":"The NE-α parasite provides you with the intelligence and awareness needed to set a trap.\\nPerforming the Damage Generator Action on a Generator applies Eruption:\\nAll affected Generators are highlighted to you in yellow.\\nThe next time any Survivor enters the Dying State by any means, all affected Generators explode and immediately start regressing, which removes the highlighted Aura.\\nInstantly regresses the Generator by -10 % of its maximum possible Progression.\\nCauses all Survivors repairing the afflicted Generators to scream and reveal their Aura to you for 8/10/12 seconds.\\n\\"It can use weapons?\\" — Jill Valentine","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/dd/IconPerks_eruption.png"},{"id":84,"name":"Deadlock","code":"deadlock","killerCode":"thecenobite","killerName":"The Cenobite","description":"You induce mental suffering by crushing any hope of escape.\\nWhenever a Generator is completed, The Entity blocks the Generator with the most progression for 20/25/30 seconds.\\nThe Aura of the blocked Generator is revealed to you in white during this time.\\n\\"Nobody escapes us.\\" — Pinhead","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d3/IconPerks_deadlock.png"},{"id":85,"name":"Hex: Plaything","code":"hexplaything","killerCode":"thecenobite","killerName":"The Cenobite","description":"A Hex that toys with a victim's suffering.\\nIf there is at least one Dull Totem remaining in the Trial Grounds, Hex: Plaything activates on a random Totem each time a Survivor is hooked for the first time:\\nThe hooked Survivor suffers from the Cursed and Oblivious Status Effects until Hex: Plaything is cleansed.\\nFor the first 90 seconds, only the Cursed Survivor is able to cleanse the Hex Totem.\\nThe Aura of Hex: Plaything's Hex Totem is revealed to the Cursed Survivor within 24/20/16 meters.\\nThe Hex effects persist as long as the related Hex Totem is standing.\\n\\"We came. Now you must come with us. Taste our pleasure.\\" — Pinhead","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/18/IconPerks_hexPlaything.png"},{"id":86,"name":"Scourge Hook: Gift of Pain","code":"scourgehookgiftofpain","killerCode":"thecenobite","killerName":"The Cenobite","description":"You are the bringer of sweet pain.\\nAt the start of the Trial, 4 random Hooks are changed into Scourge Hooks:\\nThe Auras of Scourge Hooks are revealed to you in white.\\nEach time a Survivor is unhooked from a Scourge Hook, the following effects apply:\\nThe Survivor suffers from the Hemorrhage and Mangled Status Effects until healed.\\nUpon being healed, the Survivor suffers from a 10/13/16 % Action Speed penalty to Healing and Repairing until they are injured again.\\n\\"We will tear your soul apart.\\" — Pinhead","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/26/IconPerks_scourgeHookGiftOfPain.png"},{"id":87,"name":"Grim Embrace","code":"grimembrace","killerCode":"theartist","killerName":"The Artist","description":"Your act of servitude to The Entity has not gone unnoticed.\\nEach time a Survivor is hooked for the first time, Grim Embrace gains a Token.\\nUpon reaching 4 Tokens Grim Embrace activates:\\nThe Entity blocks all Generators for 30/35/40 seconds.The Aura of the Obsession is revealed to you for 5 seconds.\\n\\"Are we nothing but prisoners to our sorrow?\\" — Carmina Mora","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_grimEmbrace.png"},{"id":88,"name":"Scourge Hook: Pain Resonance","code":"scourgehookresonance","killerCode":"theartist","killerName":"The Artist","description":"Overwhelming pain reverberates outwards.\\nAt the start of the Trial, 4 random Hooks are changed into Scourge Hooks:\\nThe Auras of Scourge Hooks are revealed to you in white.\\nEach time a Survivor is hooked on a Scourge Hook, the following effects apply:\\nThe Generator with the most Progression explodes, instantly losing 9/12/15 % of its Progression and starting to regress.\\nSurvivors repairing that Generator will scream, but not reveal their location.\\n\\"The pain spills beyond flesh/darkness staining the horizon.\\" — Girl in the Shadow by Carmina Mora","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/79/IconPerks_scourgeHookPainResonance.png"},{"id":89,"name":"Hex: Pentimento","code":"hexpentimento","killerCode":"theartist","killerName":"The Artist","description":"You reveal the true power of the Totems, hidden within their remains.\\nYou see the Auras of cleansed Totems.\\nYou can perform a ritual on a cleansed Totem to resurrect it as a Rekindled Totem.\\nFor each Rekindled Totem active at the same time, Hex: Pentimento gains an additional effect:\\n1 Totem: Decreases all Survivors' Repair speed by 20/25/30%.\\n2 Totems: Decreases all Survivors' Healing speed by 20/25/30%.\\n3 Totems: Decreases all Survivors' Recovery speed from being downed by 20/25/30%.\\n4 Totems: Decreases all Survivors' Exit Gate Opening speed by 20/25/30%.\\n5 Totems: All Totems are permanently blocked by The Entity.\\nWhen a Rekindled Totem is cleansed, its remains are consumed by The Entity and it cannot be rekindled.\\n\\"Though a pentimento is an inherently concealed piece of art, there is something to be said of the desire to discover that which is beyond.\\" — A Guide to Art & Process (1961)","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_hexPentimento.png"},{"id":90,"name":"Scourge Hook: Floods of Rage","code":"scourgehookfloodsofrage","killerCode":"theonryo","killerName":"The Onryō","description":"You form a psychic connection with The Entity and alter the rules of the Trial.\\nAt the start of the Trial, 4 random Hooks are changed into Scourge Hooks:\\nThe Auras of Scourge Hooks are revealed to you in white.\\nEach time a Survivor is unhooked from a Scourge Hook, the following effects apply:\\nThe Auras of all other Survivors are revealed for 5/6/7 seconds.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_scourgeHookFloodsOfRage.png"},{"id":91,"name":"Call of Brine","code":"callofbrine","killerCode":"theonryo","killerName":"The Onryō","description":"Your psychic abilities influence technology in devastating ways.\\nAfter performing the Damage Generator action on a Generator, Call of Brine activates for 60 seconds.\\nThe damaged Generator regresses at 115/120/125 % of the normal Regression speed and its Aura is highlighted to you in yellow.\\nReceive a Loud Noise Notification each time a Survivor hits a Good Skill Check on the affected Generator.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_callOfBrine.png"},{"id":92,"name":"Merciless Storm","code":"mercilessstorm","killerCode":"theonryo","killerName":"The Onryō","description":"Your horrible trauma is felt by everyone.\\nWhenever a Generator is repaired to 90 %, Survivors repairing it are faced with continuous Skill Checks.\\nIf they miss one or stop repairing, the Generator becomes blocked for 16/18/20 seconds.\\nMerciless Storm can only trigger once per Generator per Trial.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_mercilessStorm.png?e67f3b"},{"id":93,"name":"Dissolution","code":"dissolution","killerCode":"thedredge","killerName":"The Dredge","description":"Everything turns to dust. It is as inescapable as the coming of the night.\\nAfter 3 seconds of injuring a Survivor by any means, Dissolution activates for 12/16/20 seconds:\\nInstantly breaks the next Pallet that Survivor performs a Fast Vault across while inside your Terror Radius.\\n\\"The Garden shall be a place of perfect Joy; through Joy, nothing shall stand in our way.\\" — Otto Stamper","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_dissolution.png"},{"id":94,"name":"Darkness Revealed","code":"darknessrevealed","killerCode":"thedredge","killerName":"The Dredge","description":"In your presence, places once thought to be safe are perhaps the most dangerous.\\nSearching a Locker has the following effect:\\nThe Auras of Survivors within 8 metres of any Locker are revealed to you for 6/7/8 seconds.\\nDarkness Revealed has a cool-down of 30 seconds.\\n\\"Stay in the light, my children. In darkness, your fear will expose you.\\" — Otto Stamper","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ed/IconPerks_darknessRevealed.png"},{"id":95,"name":"Septic Touch","code":"septictouch","killerCode":"thedredge","killerName":"The Dredge","description":"The Land of the Shadows subsumes all. Healing only delays the inevitable.\\nWhenever a Survivor performs a Healing action while they are inside your Terror Radius, that Survivor suffers from the Blindness and the Exhausted Status Effects.\\nThese effects linger for 6/8/10 seconds after the Healing action is interrupted by any means.\\n\\"Do not admit to fear, or pain, or doubt. These are the seeds from which darkness grows.\\" — Otto Stamper","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconPerks_septicTouch.png"},{"id":96,"name":"Shattered Hope","code":"shatteredhope","killerCode":"all","killerName":"All","description":"To capture your prey, you must first extinguish their hope.\\nInstead of snuffing Boon Totems you destroy them.\\nDestroying a Boon Totem this way reveals the Auras of all Survivors that were within its range at that moment for 6/7/8 seconds.\\n\\"Nothing is permanent here. Nothing except our endless perdition.\\" — Unknown, Notebook","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/aa/IconPerks_shatteredHope.png"},{"id":97,"name":"Superior Anatomy","code":"superioranatomy","killerCode":"themastermind","killerName":"The Mastermind","description":"Decades of reserach have culminated in you: something faster, stronger, and more dangerous than any human.\\nWhen a Survivor performs a rushed vault within 8 metres of you, Superior Anatomy activates:\\nIncreases your Vaulting speed by 30/35/40 % the next time you vault a Window.\\nSuperior Anatomy deactivates after vaulting.\\nSuperior Anatomy has a cool-down of 30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_superiorAnatomy.png?f818ed"},{"id":98,"name":"Awakened Awareness","code":"awakenedawareness","killerCode":"themastermind","killerName":"The Mastermind","description":"Your genes have been altered to heighten your senses in intense situations.While carrying a Survivor, you benefit from the following effect:\\nThe Auras of all Survivors within 16/18/20 metres of your location are revealed to you.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/97/IconPerks_awakenedAwareness.png"},{"id":99,"name":"Terminus","code":"terminus","killerCode":"themastermind","killerName":"The Mastermind","description":"You are a brilliant tactician who prepares for every eventuality.\\nOnce the Exit Gates are powered, Terminus activates:\\nAll Survivors, who are either injured, dying, or hooked, suffer from the Broken Status Effect until the Exit Gates are opened.\\nThis effect lingers for an additional 20/25/30 seconds after the Exit Gates are open.","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4c/IconPerks_terminus.png"},{"id":100,"name":"Nowhere to Hide","code":"nowheretohide","killerCode":"theknight","killerName":"The Knight","description":"The machinations of the weak and craven draw your ire.\\nYour anger forces Survivors to reveal themselves.\\nPerforming the Damage Generator Action on a Generator triggers Nowhere to Hide:\\nThe Auras of all Survivors within 24 metres of your position are revealed to you for 3/4/5 seconds.\\n\\"Out with you, cowards! Show yourselves!\\" — Tarhos Kovács","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/29/IconPerks_nowhereToHide.png"},{"id":101,"name":"Hex: Face the Darkness","code":"hexfacethedarkness","killerCode":"theknight","killerName":"The Knight","description":"You make an example of one of your victims, forcing their allies to become awed by your power.\\nOnce you injure a Survivor by any means, if there is still a Dull Totem remaining on the Map, Hex: Face the Darkness activates and lights it, cursing that Survivor:\\nAll other Survivors will scream every 35/30/25 seconds if they are outside of the Killer's Terror Radius, revealing their Auras for 2 seconds each time.\\nHex: Face the Darkness deactivates when the Cursed Survivor either enters the Dying State or becomes Healthy, extinguishing its Totem.\\nHex: Face the Darkness is disabled for the remainder of the Trial if Survivors manage to cleanse its Hex Totem.\\n\\"I shall make an example of one. These mewling worms will never know peace.\\" — Tarhos Kovács","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconPerks_hexFaceTheDarkness.png"},{"id":102,"name":"Hubris","code":"hubris","killerCode":"theknight","killerName":"The Knight","description":"You show no mercy, especially to those foolish enough to resist.\\nWhenever you are stunned by a Survivor, that Survivor suffers from the Exposed Status Effect for 10/15/20 seconds.\\nHubris has a cool-down of 20 seconds.\\n\\"You have made a grave mistake, standing in opposition to me this day.\\" — Tarhos Kovács","icon":"https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/aa/IconPerks_hubris.png"},{"id":103,"name":"THWACK!","code":"thwack","killerCode":"theskullmerchant","killerName":"The Skull Merchant","description":"Your brutal strikes echo with terror. After breaking a Pallet or Wall, the next Survivor you hit with a Basic Attack screams, revealing their location and the Auras of all Survivors within 16 meters for 5/6/7 seconds. THWACK! has a cooldown of 60 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_thwack.png?38d700"},{"id":104,"name":"Leverage","code":"leverage","killerCode":"theskullmerchant","killerName":"The Skull Merchant","description":"You exploit every advantage. For each hooked Survivor, all other Survivors suffer a 3/4/5% penalty to Healing speed for the next 30 seconds after the hook. This effect stacks up to 3 times.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_leverage.png?38d700"},{"id":105,"name":"Game Afoot","code":"gameafoot","killerCode":"theskullmerchant","killerName":"The Skull Merchant","description":"The hunt excites you. When you are stunned by a Survivor or break a Pallet, gain 5% Haste for 8/10/12 seconds. If the Survivor stunning you is the Obsession, they become Exposed for 20 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_gameAfoot.png?32875b"},{"id":106,"name":"Genetic Limits","code":"geneticlimits","killerCode":"thesingularity","killerName":"The Singularity","description":"Your victims' biology betrays them. When a Survivor loses a Health State, they suffer from the Mangled and Haemorrhage Status Effects until healed. Additionally, their Healing speed is reduced by 15/20/25% for 30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_geneticLimits.png?41bad7"},{"id":107,"name":"Forced Hesitation","code":"forcedhesitation","killerCode":"thesingularity","killerName":"The Singularity","description":"Your presence disrupts their escape. When you hook a Survivor, all other Survivors within 24 meters suffer from the Hindered Status Effect (10% slow) for 8/10/12 seconds. Forced Hesitation has a cooldown of 40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_forcedHesitation.png?46c982"},{"id":108,"name":"Machine Learning","code":"machinelearning","killerCode":"thesingularity","killerName":"The Singularity","description":"You adapt and improve. Each time a Generator is completed, Machine Learning gains 1 Token. For each Token, your movement speed is increased by 1% and your Terror Radius is reduced by 1 meter, up to a maximum of 5/6/7 Tokens. These effects are lost when you down a Survivor.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_machineLearning.png?d42380"},{"id":109,"name":"Rapid Brutality","code":"rapidbrutality","killerCode":"thexenomorph","killerName":"The Xenomorph","description":"Your attacks are swift and relentless. After hitting a Survivor with a Basic Attack, you gain 5% Haste for 8/9/10 seconds. If you down a Survivor during this time, the Haste is extended by another 5 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_rapidBrutality.png?1c1f82"},{"id":110,"name":"Alien Instinct","code":"alieninstinct","killerCode":"thexenomorph","killerName":"The Xenomorph","description":"You are so stealthy, sometimes it seems like you appear out of nowhere.\\nWhenever you hook a Survivor, Alien Instinct activates:\\nThe Aura of the farthest injured Survivor is revealed to you for 5 seconds.\\nThat Survivor suffers from the Oblivious Status Effect for 16/18/20 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_alienInstinct.png?5e7374"},{"id":111,"name":"Ultimate Weapon","code":"ultimateweapon","killerCode":"thexenomorph","killerName":"The Xenomorph","description":"When you open a Locker, all Survivors within 24 meters scream and reveal their location, and they are afflicted with the Blindness Status Effect for 20/25/30 seconds. Ultimate Weapon has a cooldown of 40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_ultimateWeapon.png?77fee9"},{"id":112,"name":"Friends 'Til The End","code":"friendstiltheend","killerCode":"thegoodguy","killerName":"The Good Guy","description":"You know how to use their bonds against them. When you hook a Survivor who is not the Obsession, the Obsession's Aura is revealed for 4/5/6 seconds and they suffer from the Exposed Status Effect for 20 seconds. If the Obsession is hooked, another random Survivor becomes the new Obsession.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_friendsTilTheEnd.png?652a64"},{"id":113,"name":"Batteries Included","code":"batteriesincluded","killerCode":"thegoodguy","killerName":"The Good Guy","description":"Being somewhere between man and machine has its upsides.\\nWhenever you are within 12 metres of a completed Generator, you are granted a +5 % Haste Status Effect.\\nThis effect lingers for 1/3/5 second(s) after leaving the Generator's range.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_batteriesIncluded.png?9b8fbc"},{"id":114,"name":"Hex: Two Can Play","code":"hextwocanplay","killerCode":"thegoodguy","killerName":"The Good Guy","description":"A Hex that turns the Survivors' tactics against them. Whenever a Survivor blinds or stuns you, all Survivors suffer from the Blindness and Exhausted Status Effects for 30/35/40 seconds. The Hex effects persist as long as the related Hex Totem is standing.","icon":"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRgqgkSHoLTjLP61LLwMv4S3lEPKeSP71JnEg&s"},{"id":115,"name":"Unbound","code":"unbound","killerCode":"theunknown","killerName":"The Unknown","description":"You are not confined by their rules. After damaging a Generator, you can teleport to any other damaged Generator within 48 meters. This teleport has a cooldown of 40/35/30 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_unbound.png?38d700"},{"id":116,"name":"Undone","code":"undone","killerCode":"theunknown","killerName":"The Unknown","description":"Their progress is meaningless. Whenever a Survivor fails a Skill Check on a Generator, that Generator loses an additional 5% progress and you see the Aura of the Survivor who failed for 4/5/6 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_undone.png?38d700"},{"id":117,"name":"Unexpected","code":"unexpected","killerCode":"theunknown","killerName":"The Unknown","description":"You are where they least expect. After hooking a Survivor, you become Undetectable for 15/20/25 seconds. The next Basic Attack you make during this time will apply the Exposed Status Effect.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_unforeseen.png?b427d2"},{"id":118,"name":"Hex: Wretched Fate","code":"hexwretchedfate","killerCode":"thedarklord","killerName":"The Dark Lord","description":"A Hex that curses the one who dares to hope. When a Survivor cleanses or blesses any Totem, they become the Cursed Survivor and suffer from the Exposed Status Effect for 40/50/60 seconds. The Hex effects persist as long as the related Hex Totem is standing.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_HexWretchedFate.png?7e07e3"},{"id":119,"name":"Human Greed","code":"humangreed","killerCode":"thedarklord","killerName":"The Dark Lord","description":"Their desire for power is their downfall. Whenever a Survivor picks up an Item from a Chest, they scream and reveal their location, and all Chests within 32 meters become blocked for 30/40/50 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_HumanGreed.png?c7b0c7"},{"id":120,"name":"Dominance","code":"dominance","killerCode":"thedarklord","killerName":"The Dark Lord","description":"The power you wield over the land strikes terror in the hearts of all who cross your path.\\nThe first time each Chest and each Totem are interacted with by a Survivor, Dominance triggers its effect:\\nCalls upon The Entity to block it for 8/12/16 seconds.\\nThe Aura of the blocked Prop is revealed to you in white.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_Dominance.png?4c9577"},{"id":121,"name":"Weave Attunement","code":"weaveattunement","killerCode":"thel ich","killerName":"The Lich","description":"You sense the flow of magic. Whenever a Survivor picks up an Item, their Aura is revealed to you for 4/5/6 seconds. If they drop the Item, it becomes blocked by The Entity for 60 seconds, and any Survivor near it suffers from the Hindered Status Effect.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_weaveAttunement.png?d7177c"},{"id":122,"name":"Dark Arrogance","code":"darkarrogance","killerCode":"thel ich","killerName":"The Lich","description":"When everything is going right, you are an inescapable inevitability.\\nIncreases your Vaulting speed in exchange for increased vulnerability to being blinded and stunned:\\nPermanently increases the duration of Killer Blinds by any means and the duration of Pallet Stuns by +25%.\\nPermanently increases your Vaulting speed by 15/20/25%.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_darkArrogance.png?d3471f"},{"id":123,"name":"Languid Touch","code":"languidtouch","killerCode":"thel ich","killerName":"The Lich","description":"You ascend with each sacrifice. For each Survivor sacrificed or killed, you gain a permanent 2% Haste and a 2% reduction to all cooldowns, up to a maximum of 8/10/12%.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_languidTouch.png?c15e67"},{"id":124,"name":"All-Shaking Thunder","code":"allshakingthunder","killerCode":"thehoundmaster","killerName":"The Houndmaster","description":"Enemies on land and sea learned to tremble before your might.\\nAfter falling from a height, All-Shaking Thunder activates for 8/12/16 seconds:\\nIncreases the range of your Lunge Attack by +75%.\\n\\"Go on. Run. Tell your friends I'm coming for them.\\" — Portia Maye","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_allShakingThunder.png?5e7374"},{"id":125,"name":"No Quarter","code":"noquarter","killerCode":"thehoundmaster","killerName":"The Houndmaster","description":"You protect your territory.\\nWhen a Survivor interacts with a Hook, Chest, or Totem within 24 meters of you, they suffer from the Oblivious Status Effect for 20/25/30 seconds and their Aura is revealed to you for 4 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_noQuarter.png?bc4038"},{"id":126,"name":"Scourge Hook: Jagged Compass","code":"scourgehookjaggedcompass","killerCode":"thehoundmaster","killerName":"The Houndmaster","description":"Your persistence is legendary. At the start of the Trial, 4 random Hooks become Scourge Hooks. When a Survivor is unhooked from a Scourge Hook, they suffer from the Exposed Status Effect for 20/25/30 seconds. Additionally, you see the Aura of the unhooked Survivor for 4 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_scourgeHookJaggedCompass.png?38db55s"},{"id":127,"name":"Hex: Nothing But Misery","code":"hexnothingbutmisery","killerCode":"theghoul","killerName":"The Ghoul","description":"A Hex that feeds on despair. When a Survivor is put into the Dying State, all other Survivors suffer from the Mangled and Haemorrhage Status Effects until that Survivor is healed or sacrificed. The Hex effects persist as long as the related Hex Totem is standing.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconPerks_NothingButMisery.png?a9e257"},{"id":128,"name":"Forever Entwined","code":"foreverentwined","killerCode":"theghoul","killerName":"The Ghoul","description":"Your bond with your prey is unbreakable. When you hook a Survivor, their Aura is revealed to you for 5/6/7 seconds. Additionally, that Survivor suffers from the Hindered Status Effect (5% slow) for 20 seconds after being unhooked.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconPerks_ForeverEntwined.png?8070ec"},{"id":129,"name":"None Are Free","code":"nonearefree","killerCode":"theghoul","killerName":"The Ghoul","description":"You deny them escape. When a Survivor attempts to open an Exit Gate, they are faced with a difficult Skill Check. If they fail, the Gate is blocked for 15/20/25 seconds and they scream, revealing their location.","icon":"https://deadbydaylight.wiki.gg/images/T_UI_iconPerks_NoneAreFree.png?872488"},{"id":130,"name":"Help Wanted","code":"helpwanted","killerCode":"theanimatronic","killerName":"The Animatronic","description":"You lure them in. When a Survivor is within 16 meters of a Locker, they see a fake Loud Noise Notification at that Locker. If they search it, they are grabbed and put into the Dying State. Help Wanted has a cooldown of 60/50/40 seconds.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_HelpWanted.png?6b051a"},{"id":131,"name":"Phantom Fear","code":"phantomfear","killerCode":"theanimatronic","killerName":"The Animatronic","description":"Your presence haunts them. Survivors repairing Generators within your Terror Radius have their Skill Check success zones reduced by 20/25/30% and trigger more frequent Skill Checks.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_PhantomFear.png?33ffc7"},{"id":132,"name":"Haywire","code":"haywire","killerCode":"theanimatronic","killerName":"The Animatronic","description":"You cause chaos. When a Survivor fails a Skill Check on a Generator, that Generator explodes, losing 10% progress and becoming blocked for 10/12/15 seconds. All other Survivors repairing that Generator scream and reveal their location.","icon":"https://deadbydaylight.wiki.gg/images/IconPerks_Haywire.png?f60f00"},{"id":133,"name":"Hex: Hive Mind","code":"hexhive","killerCode":"thefirst","killerName":"The First","description":"You found yourself connected to something dark and unknowable... and you embraced it. The first time you hook any Survivor, a random Dull Totem becomes a Hex Totem, provided that a Dull Totem remains in the Trial Grounds. Generators are highlighted; the intensity of the generator's Auras reveals their repair progress. As soon as a total of 4 generators have been completed in the Trial: All remaining generators explode, lose 6/8/10% progress, and start regressing. The associated Hex Totem becomes dull, and this perk becomes disabled for the remainder of the trial. The Hex Effects persist until the Hex Totem is either blessed or cleansed by a Survivor, disabling it for the remainder of the Trial. 'You... let us in. And now, you are going to have to let us stay' — Henry Creel","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_HexHiveMind.png?db4284"},{"id":134,"name":"Secret Project","code":"secretproject","killerCode":"thefirst","killerName":"The First","description":"Raised to be weapon, you broke free with the very skills your captors honed within you. Whenever a Totem is blessed or cleansed, a random unblocked generator becomes blocked for 20/25/30 seconds. Whenever any number of Generators become blocked, you gain the Undetectable Status Effect for 30 seconds. 'You are a prisoner here, just like me' — Henry Creel","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_SecretProject.png?139f37"},{"id":135,"name":"Turn Back the Clock","code":"turnbacktheclock","killerCode":"thefirst","killerName":"The First","description":"Resist as they might, time marches on, and your master plan comes closer to fruition. After hooking a Survivor, for 40/50/60 seconds, press the Active Ability button to make a target generator within 20 meters explode, lose -10% progress, and start regressing. 'Nothing will happen to you... Nothing that you don't deserve!' — Henry Creel","icon":"https://deadbydaylight.wiki.gg/images/IconsPerks_TurnBackTheClock.png?17d1df"}]`);export{l as F,d as a,h as k,c as s};
